SELECT id INTO v_book FROM textbooks WHERE tenant_id = v_tenant AND slug = 'wolfwhale-biology-30';

-- ----------------------------------------------------------------------------
-- Chapter 1: Biochemistry — Molecules of Life
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 1, 'Biochemistry: Molecules of Life', 'biochemistry-molecules-of-life',
  'An introduction to the four major classes of biological macromolecules — carbohydrates, lipids, proteins, and nucleic acids — as well as the essential role of water in living systems.',
  '[
    {"type": "heading", "level": 1, "text": "Biochemistry: Molecules of Life"},
    {"type": "text", "content": "Every living organism on Earth, from the lichen clinging to granite outcrops on the Canadian Shield to the bison grazing across the Saskatchewan prairies, is built from the same fundamental set of molecules. Understanding these molecules — their structures, properties, and interactions — is the gateway to understanding life itself. In this chapter we examine the four major classes of biological macromolecules and the remarkable solvent that makes their chemistry possible: water."},
    {"type": "heading", "level": 2, "text": "Water: The Solvent of Life"},
    {"type": "text", "content": "Water makes up roughly 60–70 percent of the mass of most organisms. Its unique properties arise from the polarity of the water molecule and the hydrogen bonds that form between neighbouring molecules. These hydrogen bonds give water a high specific heat capacity, meaning that large bodies of water such as Saskatchewan''s Lake Diefenbaker resist rapid temperature changes — a property critical for aquatic organisms. Water''s cohesion allows it to travel from roots to leaf tips in towering boreal spruce trees, while its role as a universal solvent lets it carry dissolved nutrients through the bloodstream or the xylem of a plant."},
    {"type": "callout", "style": "info", "title": "Why Polarity Matters", "content": "A water molecule has a bent shape with oxygen at the vertex. Oxygen is more electronegative than hydrogen, so the shared electrons spend more time near the oxygen atom. This creates a partial negative charge near the oxygen and partial positive charges near the hydrogens — making water a polar molecule capable of dissolving ionic and polar substances."},
    {"type": "heading", "level": 2, "text": "Carbohydrates"},
    {"type": "text", "content": "Carbohydrates are organic compounds composed of carbon, hydrogen, and oxygen, typically in a ratio near 1:2:1. They serve two primary roles in organisms: rapid energy supply and structural support. The simplest carbohydrates are monosaccharides such as glucose (C₆H₁₂O₆), a six-carbon sugar that serves as the main fuel molecule for cellular respiration. When two monosaccharides join by a dehydration synthesis reaction, they form a disaccharide — for example, sucrose (table sugar) is formed from glucose and fructose. Longer chains of monosaccharides produce polysaccharides: starch and glycogen store energy in plants and animals respectively, while cellulose provides rigid structural support in plant cell walls. Saskatchewan wheat fields produce enormous quantities of starch each growing season, storing solar energy in chemical bonds that feed millions of people worldwide."},
    {"type": "heading", "level": 2, "text": "Lipids"},
    {"type": "text", "content": "Lipids are a diverse group of hydrophobic molecules that include fats, oils, phospholipids, and steroids. Triglycerides — three fatty acid chains attached to a glycerol backbone — store more than twice the energy per gram compared with carbohydrates, making them efficient long-term energy reserves. Saturated fatty acids have no carbon–carbon double bonds and pack tightly, forming solid fats at room temperature, while unsaturated fatty acids contain one or more double bonds that introduce kinks in the chain, producing liquid oils. Canola, one of Saskatchewan''s most important crops, yields oil rich in unsaturated fatty acids that is valued for its health properties. Phospholipids, with their hydrophilic head and hydrophobic tails, self-assemble into the bilayer membranes that surround every cell."},
    {"type": "heading", "level": 2, "text": "Proteins"},
    {"type": "text", "content": "Proteins are polymers of amino acids linked by peptide bonds. Twenty different amino acids combine in varying sequences to create an astonishing diversity of proteins. The sequence of amino acids (primary structure) dictates how the chain folds into local patterns such as alpha helices and beta sheets (secondary structure), then into a three-dimensional shape (tertiary structure), and sometimes into multi-subunit complexes (quaternary structure). Proteins serve as enzymes that catalyse reactions, structural elements like collagen in connective tissue, transport molecules like haemoglobin, and signalling molecules like insulin. The shape of a protein is essential to its function — if that shape is disrupted by heat or pH changes (denaturation), the protein loses its biological activity."},
    {"type": "callout", "style": "example", "title": "Worked Example: Dehydration Synthesis", "content": "Question: Two glucose molecules undergo dehydration synthesis. What products form?\n\nStep 1: Identify the reactants — two glucose molecules (C₆H₁₂O₆).\nStep 2: In dehydration synthesis, a hydroxyl group (–OH) from one molecule and a hydrogen atom (–H) from the other are removed, forming a water molecule.\nStep 3: A covalent bond (glycosidic bond) forms between the two glucose residues.\n\nAnswer: The products are one molecule of maltose (a disaccharide, C₁₂H₂₂O₁₁) and one molecule of water (H₂O). The reverse reaction — hydrolysis — would break maltose back into two glucose molecules by adding water."},
    {"type": "heading", "level": 2, "text": "Nucleic Acids"},
    {"type": "text", "content": "Nucleic acids — DNA and RNA — are polymers of nucleotides. Each nucleotide contains a five-carbon sugar, a phosphate group, and a nitrogenous base. DNA uses deoxyribose as its sugar and the bases adenine, thymine, guanine, and cytosine. RNA uses ribose and replaces thymine with uracil. DNA stores the hereditary instructions for building proteins, while RNA plays multiple roles in reading and executing those instructions. We will explore nucleic acid structure in far greater detail in Chapter 4."},
    {"type": "callout", "style": "tip", "title": "Indigenous Knowledge: Plants as Biochemical Factories", "content": "Indigenous Peoples of the northern plains have long understood that different parts of a plant offer different medicinal and nutritional properties. For example, Cree and Métis knowledge holders recognize that the inner bark of certain willow species eases pain — a property we now attribute to salicin, a chemical relative of acetylsalicylic acid (ASA). Similarly, wild mint was used as a digestive aid, while Labrador tea provided a source of antioxidants. These traditions reflect a sophisticated, observation-based understanding of plant biochemistry developed over thousands of years of careful experimentation and oral knowledge transfer."},
    {"type": "quiz", "question": "Which class of macromolecule stores the most energy per gram?", "options": ["Carbohydrates", "Lipids", "Proteins", "Nucleic acids"], "correctIndex": 1, "explanation": "Lipids (specifically triglycerides) store more than 9 kilocalories per gram, compared with roughly 4 kilocalories per gram for carbohydrates and proteins. This makes lipids the most energy-dense class of biological macromolecule."},
    {"type": "quiz", "question": "During dehydration synthesis, what small molecule is released when a bond forms between two monomers?", "options": ["Carbon dioxide", "Oxygen gas", "Water", "ATP"], "correctIndex": 2, "explanation": "Dehydration synthesis (also called condensation) removes a water molecule (H₂O) as a covalent bond forms between two monomers. The reverse reaction, hydrolysis, adds water to break the bond."}
  ]'::jsonb,
  '[
    {"term": "Macromolecule", "definition": "A large, complex molecule such as a protein, nucleic acid, carbohydrate, or lipid, typically formed by polymerisation of smaller subunits."},
    {"term": "Monosaccharide", "definition": "The simplest form of carbohydrate, a single sugar unit such as glucose or fructose."},
    {"term": "Polysaccharide", "definition": "A long chain of monosaccharides linked by glycosidic bonds; examples include starch, glycogen, and cellulose."},
    {"term": "Triglyceride", "definition": "A lipid composed of three fatty acid chains bonded to a glycerol molecule; the main form of stored fat in organisms."},
    {"term": "Amino Acid", "definition": "The monomer of proteins, consisting of a central carbon bonded to an amino group, a carboxyl group, a hydrogen atom, and a variable R group."},
    {"term": "Dehydration Synthesis", "definition": "A chemical reaction that joins two monomers by removing a water molecule, forming a covalent bond."},
    {"term": "Hydrolysis", "definition": "A chemical reaction that breaks a covalent bond between monomers by adding a water molecule."},
    {"term": "Nucleotide", "definition": "The monomer of nucleic acids, consisting of a five-carbon sugar, a phosphate group, and a nitrogenous base."},
    {"term": "Hydrogen Bond", "definition": "A weak attraction between a partially positive hydrogen atom and a partially negative atom (often oxygen or nitrogen) on another molecule."}
  ]'::jsonb,
  'Indigenous Peoples of the northern plains have long understood that different plant parts offer distinct medicinal and nutritional properties — reflecting a sophisticated, observation-based understanding of plant biochemistry refined over thousands of years.',
  35, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 2: Cell Structure & Function
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 2, 'Cell Structure & Function', 'cell-structure-and-function',
  'A detailed examination of cell organelles, membrane structure and transport, and how cells communicate with one another.',
  '[
    {"type": "heading", "level": 1, "text": "Cell Structure & Function"},
    {"type": "text", "content": "The cell is the fundamental unit of life. Whether we look at a single-celled bacterium thriving in a Saskatchewan slough or a neuron stretching the length of a moose''s leg, all cells share certain features: a plasma membrane, genetic material, ribosomes, and cytoplasm. Beyond these basics, eukaryotic cells — found in protists, fungi, plants, and animals — possess membrane-bound organelles that compartmentalise biochemical processes. In this chapter we explore these structures and the mechanisms by which materials cross the plasma membrane."},
    {"type": "heading", "level": 2, "text": "Prokaryotic vs Eukaryotic Cells"},
    {"type": "text", "content": "Prokaryotic cells, which include bacteria and archaea, lack a membrane-bound nucleus. Their DNA exists as a single circular chromosome in a region called the nucleoid. Eukaryotic cells contain a true nucleus enclosed by a double membrane (the nuclear envelope) and possess additional organelles such as mitochondria, endoplasmic reticulum, and Golgi apparatus. Plant cells additionally have chloroplasts, a central vacuole, and a rigid cell wall made of cellulose. Understanding the distinction between these two cell types is essential, because many disease-fighting strategies (such as antibiotics) exploit structural differences unique to prokaryotes."},
    {"type": "heading", "level": 2, "text": "Major Organelles of Eukaryotic Cells"},
    {"type": "text", "content": "The nucleus houses the cell''s DNA and is the site of DNA replication and transcription. Surrounding the nucleus, the rough endoplasmic reticulum (studded with ribosomes) synthesises proteins destined for secretion or membrane insertion, while the smooth endoplasmic reticulum synthesises lipids and detoxifies certain substances. The Golgi apparatus receives, modifies, sorts, and packages proteins and lipids into vesicles for transport. Mitochondria are the powerhouses of the cell, generating ATP through cellular respiration — a process we will examine in Chapter 3. In plant cells, chloroplasts capture light energy and convert it to chemical energy via photosynthesis. Lysosomes contain digestive enzymes that break down worn-out organelles and ingested materials, while peroxisomes neutralise toxic hydrogen peroxide."},
    {"type": "callout", "style": "info", "title": "The Endomembrane System", "content": "The nuclear envelope, endoplasmic reticulum, Golgi apparatus, lysosomes, and plasma membrane are physically or functionally connected through vesicle transport. This interconnected network is called the endomembrane system. Vesicles bud from one compartment and fuse with another, shuttling proteins and lipids to their correct destinations — much like a postal system within the cell."},
    {"type": "heading", "level": 2, "text": "The Plasma Membrane and Transport"},
    {"type": "text", "content": "The plasma membrane is a fluid mosaic of phospholipids, cholesterol, and proteins. Its selective permeability controls what enters and leaves the cell. Small, nonpolar molecules like oxygen and carbon dioxide cross freely by simple diffusion. Water moves by osmosis — a special case of diffusion across a selectively permeable membrane. Polar molecules and ions require assistance from transport proteins embedded in the membrane: channel proteins form hydrophilic pores, while carrier proteins change shape to shuttle specific solutes. When transport occurs down the concentration gradient, it is called facilitated diffusion and requires no energy. Active transport moves solutes against their concentration gradient and requires ATP — the sodium-potassium pump is a classic example, maintaining the electrochemical gradient essential for nerve impulse transmission."},
    {"type": "callout", "style": "example", "title": "Worked Example: Osmosis in Plant Cells", "content": "Question: A plant cell with a solute concentration of 0.4 mol/L is placed in a solution of 0.2 mol/L. Describe what happens.\n\nStep 1: Compare concentrations. The cell interior (0.4 mol/L) is hypertonic relative to the surrounding solution (0.2 mol/L).\nStep 2: Water moves by osmosis from the region of lower solute concentration (outside) to higher solute concentration (inside the cell).\nStep 3: The cell swells as water enters. In a plant cell, the rigid cell wall prevents bursting — instead the cell becomes turgid, which is the normal, healthy state for plant cells.\n\nAnswer: Water enters the cell by osmosis, and the cell becomes turgid. If the external solution were hypertonic instead, water would leave and the cell would plasmolyse (the membrane pulling away from the cell wall)."},
    {"type": "heading", "level": 2, "text": "Cell Communication"},
    {"type": "text", "content": "Cells do not operate in isolation. They constantly send and receive chemical signals that coordinate growth, immune responses, and metabolic activity. In signal transduction, a signalling molecule (ligand) binds to a receptor on the target cell''s surface. This triggers a cascade of intracellular events — often involving relay proteins and second messengers such as cyclic AMP — that ultimately alter gene expression or enzyme activity. Hormones like insulin travel through the bloodstream to reach distant target cells (endocrine signalling), while neurotransmitters cross a tiny synaptic gap to signal adjacent neurons (paracrine signalling). Disruptions in cell signalling pathways can lead to diseases such as diabetes or cancer."},
    {"type": "callout", "style": "tip", "title": "Indigenous Knowledge: Birch Bark and Cellular Defence", "content": "Cree and Dene knowledge holders have traditionally used birch bark preparations to treat skin infections and wounds. Contemporary research has identified betulin and betulinic acid in birch bark — compounds that exhibit antimicrobial and anti-inflammatory properties at the cellular level. These compounds appear to influence cell membrane integrity in bacteria and modulate immune cell signalling in mammals, providing a molecular basis for traditional healing practices passed down through generations in the boreal forests of northern Saskatchewan."},
    {"type": "quiz", "question": "Which organelle is responsible for modifying, sorting, and packaging proteins into vesicles?", "options": ["Rough endoplasmic reticulum", "Golgi apparatus", "Lysosome", "Mitochondrion"], "correctIndex": 1, "explanation": "The Golgi apparatus (also called the Golgi body or Golgi complex) receives proteins from the rough ER, modifies them (e.g., by adding carbohydrate chains), sorts them, and packages them into vesicles for transport to their final destinations within or outside the cell."},
    {"type": "quiz", "question": "A red blood cell is placed in distilled water. What will occur?", "options": ["The cell will shrink (crenation)", "The cell will swell and may burst (lysis)", "Nothing — the cell is in an isotonic solution", "The cell will become turgid"], "correctIndex": 1, "explanation": "Distilled water is hypotonic relative to the red blood cell''s cytoplasm. Water moves into the cell by osmosis, causing it to swell. Unlike plant cells, animal cells lack a rigid cell wall, so the cell may burst (lyse) if too much water enters."}
  ]'::jsonb,
  '[
    {"term": "Organelle", "definition": "A membrane-bound or distinct structure within a eukaryotic cell that performs a specific function, such as the nucleus or mitochondrion."},
    {"term": "Plasma Membrane", "definition": "The selectively permeable phospholipid bilayer that forms the outer boundary of a cell, controlling the movement of substances in and out."},
    {"term": "Osmosis", "definition": "The net movement of water molecules across a selectively permeable membrane from a region of lower solute concentration to a region of higher solute concentration."},
    {"term": "Active Transport", "definition": "The movement of molecules across a cell membrane against their concentration gradient, requiring energy (ATP)."},
    {"term": "Facilitated Diffusion", "definition": "The passive movement of molecules across a membrane through transport proteins, down the concentration gradient without energy input."},
    {"term": "Hypertonic", "definition": "Describes a solution with a higher solute concentration relative to another solution (e.g., the cell interior)."},
    {"term": "Signal Transduction", "definition": "The process by which a cell converts an extracellular signal (ligand binding to a receptor) into a specific intracellular response."},
    {"term": "Endomembrane System", "definition": "The interconnected network of membranes within a eukaryotic cell, including the nuclear envelope, ER, Golgi, lysosomes, and plasma membrane."}
  ]'::jsonb,
  'Cree and Dene knowledge holders have traditionally used birch bark preparations to treat infections — compounds like betulin in the bark influence bacterial cell membranes and immune cell signalling, providing a molecular basis for traditional healing practices.',
  40, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 3: Cellular Respiration & Photosynthesis
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 3, 'Cellular Respiration & Photosynthesis', 'cellular-respiration-and-photosynthesis',
  'How cells harvest energy from glucose through glycolysis, the Krebs cycle, and the electron transport chain, and how photosynthetic organisms capture light energy through the Calvin cycle.',
  '[
    {"type": "heading", "level": 1, "text": "Cellular Respiration & Photosynthesis"},
    {"type": "text", "content": "Life requires a continuous supply of energy. Photosynthetic organisms — plants, algae, and certain bacteria — capture radiant energy from the sun and store it in the bonds of glucose molecules. Nearly all organisms then extract that stored energy through cellular respiration, converting glucose into ATP, the universal energy currency of cells. Together, photosynthesis and cellular respiration form a grand energy cycle that sustains virtually every ecosystem on the planet, from Saskatchewan''s boreal forests to the deepest ocean floor."},
    {"type": "heading", "level": 2, "text": "Overview of Cellular Respiration"},
    {"type": "text", "content": "Cellular respiration is the metabolic process by which cells break down glucose (C₆H₁₂O₆) in the presence of oxygen to produce carbon dioxide, water, and ATP. The overall equation is: C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O + ~36–38 ATP. This process occurs in three main stages: glycolysis (in the cytoplasm), the Krebs cycle (in the mitochondrial matrix), and the electron transport chain (along the inner mitochondrial membrane). Each stage progressively extracts energy from glucose and stores it in ATP and electron carriers like NADH and FADH₂."},
    {"type": "heading", "level": 2, "text": "Glycolysis"},
    {"type": "text", "content": "Glycolysis (literally ''sugar splitting'') occurs in the cytoplasm and does not require oxygen. A six-carbon glucose molecule is split into two three-carbon molecules of pyruvate through a series of ten enzyme-catalysed reactions. The process consumes 2 ATP molecules as an initial investment but produces 4 ATP by substrate-level phosphorylation, yielding a net gain of 2 ATP per glucose. Two molecules of NAD⁺ are also reduced to NADH, which carry high-energy electrons to the electron transport chain. If oxygen is unavailable, the cell may instead undergo fermentation — producing either ethanol and CO₂ (in yeast) or lactate (in animal muscle cells) — to regenerate NAD⁺ and keep glycolysis running."},
    {"type": "heading", "level": 2, "text": "The Krebs Cycle"},
    {"type": "text", "content": "Before entering the Krebs cycle, each pyruvate molecule is converted to acetyl-CoA in the mitochondrial matrix, releasing one CO₂ and producing one NADH. Acetyl-CoA then enters the Krebs cycle (also called the citric acid cycle), a series of eight reactions that completely oxidise the acetyl group to CO₂. For each turn of the cycle, the cell gains 3 NADH, 1 FADH₂, and 1 GTP (equivalent to 1 ATP). Since each glucose produces two acetyl-CoA molecules, the Krebs cycle turns twice per glucose, generating a total of 6 NADH, 2 FADH₂, and 2 ATP equivalents."},
    {"type": "heading", "level": 2, "text": "Electron Transport Chain and Oxidative Phosphorylation"},
    {"type": "text", "content": "The electron transport chain (ETC) is embedded in the inner mitochondrial membrane. NADH and FADH₂ donate their high-energy electrons to a series of protein complexes (Complexes I–IV). As electrons pass through these complexes, energy is released and used to pump hydrogen ions (H⁺) from the mitochondrial matrix into the intermembrane space, creating an electrochemical gradient. Hydrogen ions then flow back into the matrix through ATP synthase, a molecular turbine that harnesses the proton-motive force to phosphorylate ADP into ATP — a process called chemiosmosis. Oxygen serves as the final electron acceptor, combining with electrons and H⁺ to form water. This stage produces roughly 32–34 ATP per glucose, making it by far the most productive stage of aerobic respiration."},
    {"type": "callout", "style": "example", "title": "Worked Example: ATP Accounting", "content": "Question: Summarise the ATP yield from the complete aerobic respiration of one glucose molecule.\n\nGlycolysis: 2 ATP (net) + 2 NADH\nPyruvate oxidation: 2 NADH (one per pyruvate)\nKrebs cycle (×2 turns): 2 ATP + 6 NADH + 2 FADH₂\nElectron transport chain: each NADH yields ~2.5 ATP; each FADH₂ yields ~1.5 ATP\n\nTotal NADH: 2 + 2 + 6 = 10 → 10 × 2.5 = 25 ATP\nTotal FADH₂: 2 → 2 × 1.5 = 3 ATP\nDirect ATP/GTP: 2 + 2 = 4 ATP\n\nGrand total: 25 + 3 + 4 = ~32 ATP per glucose (theoretical maximum ~36–38 depending on shuttle system used)."},
    {"type": "heading", "level": 2, "text": "Photosynthesis: Capturing Light Energy"},
    {"type": "text", "content": "Photosynthesis occurs in chloroplasts and can be summarised as: 6CO₂ + 6H₂O + light energy → C₆H₁₂O₆ + 6O₂. It proceeds in two stages. The light-dependent reactions occur in the thylakoid membranes, where chlorophyll and other pigments absorb light energy. This energy is used to split water molecules (photolysis), releasing O₂ as a by-product and generating ATP and NADPH. The light-independent reactions (Calvin cycle) take place in the stroma, where CO₂ is fixed into an organic molecule by the enzyme RuBisCO and then reduced using ATP and NADPH to produce glyceraldehyde-3-phosphate (G3P). Three turns of the Calvin cycle, each fixing one CO₂, are needed to produce one G3P molecule; six turns produce enough G3P to assemble one glucose molecule."},
    {"type": "callout", "style": "info", "title": "Connecting the Two Pathways", "content": "Photosynthesis and cellular respiration are complementary processes. Photosynthesis uses CO₂ and H₂O to build glucose and release O₂. Cellular respiration uses glucose and O₂ to produce CO₂, H₂O, and ATP. The oxygen released by Saskatchewan''s vast forests and crop fields during summer photosynthesis is consumed by organisms through respiration, while the CO₂ they exhale is recaptured by plants — a continuous biogeochemical cycle."},
    {"type": "callout", "style": "tip", "title": "Indigenous Knowledge: Seasonal Energy Cycles", "content": "Plains Cree and Saulteaux communities have long observed the seasonal rhythms of plant growth and dormancy — what biologists describe as the balance between photosynthesis and respiration. Elders note that trees ''breathe in'' strongly during the long summer days, storing energy that sustains the ecosystem through winter. Traditional harvesting calendars align with peak energy storage in plants: berries collected in late summer contain maximum sugars, roots dug in autumn hold their greatest starch reserves, and birch sap flows in early spring when stored sugars mobilise. These observations mirror our scientific understanding of photosynthetic productivity and carbohydrate storage."},
    {"type": "quiz", "question": "In which stage of cellular respiration is the greatest number of ATP molecules produced?", "options": ["Glycolysis", "Krebs cycle", "Electron transport chain / oxidative phosphorylation", "Pyruvate oxidation"], "correctIndex": 2, "explanation": "The electron transport chain and oxidative phosphorylation produce approximately 32–34 of the ~36–38 total ATP molecules generated per glucose. This makes it by far the most productive stage, driven by the proton gradient and chemiosmosis at ATP synthase."},
    {"type": "quiz", "question": "What is the role of oxygen in aerobic cellular respiration?", "options": ["It is a reactant in the Calvin cycle", "It donates electrons to Complex I of the ETC", "It serves as the final electron acceptor in the electron transport chain", "It catalyses the conversion of pyruvate to acetyl-CoA"], "correctIndex": 2, "explanation": "Oxygen acts as the final electron acceptor at the end of the electron transport chain (Complex IV). After accepting electrons and combining with H⁺ ions, it forms water. Without oxygen to accept electrons, the ETC stalls and ATP production via oxidative phosphorylation ceases."}
  ]'::jsonb,
  '[
    {"term": "ATP (Adenosine Triphosphate)", "definition": "The primary energy currency of cells, consisting of adenine, ribose, and three phosphate groups. Energy is released when the terminal phosphate bond is hydrolysed."},
    {"term": "Glycolysis", "definition": "The anaerobic metabolic pathway in the cytoplasm that splits one glucose molecule into two pyruvate molecules, yielding a net gain of 2 ATP and 2 NADH."},
    {"term": "Krebs Cycle", "definition": "A cyclic series of reactions in the mitochondrial matrix that oxidises acetyl-CoA to CO₂, generating NADH, FADH₂, and GTP."},
    {"term": "Electron Transport Chain", "definition": "A series of protein complexes in the inner mitochondrial membrane that transfer electrons from NADH and FADH₂ to oxygen, driving ATP synthesis by chemiosmosis."},
    {"term": "Chemiosmosis", "definition": "The production of ATP driven by the flow of hydrogen ions (H⁺) down their electrochemical gradient through ATP synthase."},
    {"term": "Photolysis", "definition": "The splitting of water molecules by light energy during the light-dependent reactions of photosynthesis, releasing O₂, H⁺, and electrons."},
    {"term": "Calvin Cycle", "definition": "The light-independent reactions of photosynthesis in the chloroplast stroma, where CO₂ is fixed and reduced to produce G3P using ATP and NADPH."},
    {"term": "RuBisCO", "definition": "Ribulose-1,5-bisphosphate carboxylase/oxygenase — the enzyme that catalyses the fixation of CO₂ in the first step of the Calvin cycle."},
    {"term": "Fermentation", "definition": "An anaerobic pathway that regenerates NAD⁺ from NADH so glycolysis can continue, producing ethanol + CO₂ (alcoholic) or lactate (lactic acid)."}
  ]'::jsonb,
  'Plains Cree and Saulteaux communities have long observed seasonal plant energy cycles — harvesting berries at peak sugar content, digging roots when starch reserves are greatest — observations that mirror our understanding of photosynthetic productivity.',
  45, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 4: DNA Structure & Replication
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 4, 'DNA Structure & Replication', 'dna-structure-and-replication',
  'An exploration of the double-helix model, the rules of base pairing, and the molecular machinery that copies DNA with remarkable fidelity before every cell division.',
  '[
    {"type": "heading", "level": 1, "text": "DNA Structure & Replication"},
    {"type": "text", "content": "Every trait you carry — from eye colour to susceptibility to certain diseases — is encoded in the sequence of roughly three billion nucleotide base pairs coiled inside nearly every cell of your body. Deoxyribonucleic acid, or DNA, is simultaneously one of the simplest and most information-rich molecules in nature. Understanding its architecture and how cells duplicate it faithfully is essential to understanding genetics, evolution, and modern biotechnology."},
    {"type": "heading", "level": 2, "text": "The Double Helix"},
    {"type": "text", "content": "DNA is a double-stranded polymer composed of nucleotide monomers. Each nucleotide consists of a deoxyribose sugar, a phosphate group, and one of four nitrogenous bases: adenine (A), thymine (T), guanine (G), or cytosine (C). The two strands run antiparallel — one oriented 5'' to 3'', the other 3'' to 5'' — and are held together by hydrogen bonds between complementary bases. Adenine pairs with thymine via two hydrogen bonds, and guanine pairs with cytosine via three hydrogen bonds. This strict base-pairing rule, first deduced from Chargaff''s data and confirmed by the X-ray crystallography of Franklin and the modelling work of Watson and Crick in 1953, explains why the two strands carry identical information in complementary form. The paired strands twist around a common axis into the iconic right-handed double helix, with the sugar-phosphate backbones forming the outer rails and the base pairs forming the inner rungs."},
    {"type": "callout", "style": "info", "title": "Chargaff''s Rules", "content": "Erwin Chargaff observed that in any DNA sample, the amount of adenine always equals the amount of thymine, and the amount of guanine always equals the amount of cytosine (A = T; G = C). This 1:1 ratio is a direct consequence of complementary base pairing and provided a crucial clue to the double-helix structure before it was solved crystallographically."},
    {"type": "heading", "level": 2, "text": "Semiconservative Replication"},
    {"type": "text", "content": "Before a cell divides, it must duplicate its entire genome so each daughter cell receives a complete copy. DNA replication is described as semiconservative: the double helix unwinds and each original strand serves as a template for a new complementary strand. As a result, each daughter DNA molecule consists of one parental strand and one newly synthesised strand. This was elegantly demonstrated by the Meselson-Stahl experiment in 1958, which used heavy nitrogen (¹⁵N) to distinguish old and new DNA strands by density."},
    {"type": "heading", "level": 2, "text": "The Replication Machinery"},
    {"type": "text", "content": "Replication begins at specific sequences called origins of replication and proceeds bidirectionally. The enzyme helicase unwinds and separates the two strands at the replication fork, while single-strand binding proteins stabilise the exposed template strands. Because DNA polymerase can only add nucleotides to an existing 3''-OH group, a short RNA primer — synthesised by an enzyme called primase — provides the starting point. DNA polymerase III then extends the new strand in the 5''-to-3'' direction, reading the template 3'' to 5''. On the leading strand, synthesis is continuous; on the lagging strand, synthesis proceeds in short fragments called Okazaki fragments, which are later joined by DNA ligase after the RNA primers are replaced. DNA polymerase also has proofreading ability, removing mismatched bases immediately after insertion. Additional repair enzymes survey the completed DNA and correct any errors that slipped through, achieving an overall error rate of roughly one mistake per billion base pairs copied."},
    {"type": "callout", "style": "example", "title": "Worked Example: Base Pairing", "content": "Question: A template strand of DNA reads 3''-ATCGGCTA-5''. Write the complementary new strand in the correct orientation.\n\nStep 1: DNA polymerase reads the template 3'' to 5'' and synthesises the new strand 5'' to 3''.\nStep 2: Apply base-pairing rules (A pairs with T; G pairs with C):\n  Template:  3''-A T C G G C T A-5''\n  New strand: 5''-T A G C C G A T-3''\n\nAnswer: The new strand is 5''-TAGCCGAT-3''. Note that the new strand is antiparallel to the template."},
    {"type": "callout", "style": "tip", "title": "Indigenous Knowledge: Heredity and Oral Tradition", "content": "Long before modern genetics, Indigenous Peoples across the prairies carefully managed the heredity of plants and animals through selective harvesting and breeding. Nakoda and Plains Cree communities selected seeds from the healthiest, most productive individuals each season — an empirical application of hereditary principles that maintained locally adapted varieties of crops and facilitated the survival of domesticated species across generations. This traditional plant stewardship mirrors what we now understand as selective pressure acting on heritable genetic variation."},
    {"type": "quiz", "question": "Which enzyme is responsible for unwinding the DNA double helix at the replication fork?", "options": ["DNA polymerase", "Ligase", "Helicase", "Primase"], "correctIndex": 2, "explanation": "Helicase breaks the hydrogen bonds between base pairs and separates the two DNA strands at the replication fork, making each strand available as a template. DNA polymerase synthesises the new strand, primase makes the RNA primer, and ligase joins Okazaki fragments."},
    {"type": "quiz", "question": "DNA replication is called semiconservative because:", "options": ["Only half of the genome is copied each cycle", "Each new double helix contains one original strand and one new strand", "The process conserves energy by using existing nucleotides", "Half of the errors are corrected by proofreading enzymes"], "correctIndex": 1, "explanation": "Semiconservative replication means that each daughter DNA molecule retains one parental (original) strand paired with one newly synthesised strand. This was proven by the Meselson-Stahl experiment using isotopically labelled nitrogen."}
  ]'::jsonb,
  '[
    {"term": "Double Helix", "definition": "The twisted-ladder structure of DNA formed by two antiparallel polynucleotide strands held together by hydrogen bonds between complementary base pairs."},
    {"term": "Base Pairing", "definition": "The specific hydrogen-bonding relationship between complementary nitrogenous bases: adenine with thymine (in DNA) and guanine with cytosine."},
    {"term": "Helicase", "definition": "An enzyme that unwinds and separates the two strands of the DNA double helix at the replication fork."},
    {"term": "DNA Polymerase", "definition": "An enzyme that synthesises a new DNA strand by adding complementary nucleotides to an existing template strand, always working 5'' to 3''."},
    {"term": "Okazaki Fragment", "definition": "A short segment of DNA synthesised on the lagging strand template during replication, later joined into a continuous strand by DNA ligase."},
    {"term": "Semiconservative Replication", "definition": "The mode of DNA replication in which each daughter molecule consists of one original (parental) strand and one newly synthesised strand."},
    {"term": "Origin of Replication", "definition": "A specific DNA sequence where replication begins; eukaryotic chromosomes have multiple origins to speed up the copying process."},
    {"term": "Proofreading", "definition": "The ability of DNA polymerase to detect and remove incorrectly inserted nucleotides immediately after they are added, greatly reducing replication errors."}
  ]'::jsonb,
  'Nakoda and Plains Cree communities managed heredity through careful seed selection each season — an empirical application of hereditary principles that maintained locally adapted plant varieties long before the molecular basis of inheritance was understood.',
  38, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 5: Gene Expression
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 5, 'Gene Expression', 'gene-expression',
  'How genetic information flows from DNA to RNA to protein through transcription and translation, and how cells precisely regulate which genes are active at any given time.',
  '[
    {"type": "heading", "level": 1, "text": "Gene Expression"},
    {"type": "text", "content": "A gene is a segment of DNA that encodes the instructions for building a functional product — almost always a protein. Yet every cell in your body carries the same DNA, from liver cells to neurons to skin cells. What makes them different is which genes they express. Gene expression is the process by which information encoded in DNA is used to direct the synthesis of proteins, and its regulation determines cellular identity, development, and response to the environment."},
    {"type": "heading", "level": 2, "text": "Transcription: DNA to RNA"},
    {"type": "text", "content": "Transcription is the process of copying a gene''s sequence from DNA into a complementary strand of messenger RNA (mRNA). It occurs in the nucleus and is carried out by the enzyme RNA polymerase. Transcription begins when RNA polymerase binds to a promoter — a specific DNA sequence upstream of the gene. The polymerase unwinds a short stretch of DNA and reads the template strand 3'' to 5'', assembling an mRNA strand in the 5'' to 3'' direction using RNA nucleotides (which include uracil instead of thymine). When RNA polymerase reaches a termination sequence, it detaches and releases the completed pre-mRNA. In eukaryotes, this pre-mRNA is extensively processed before leaving the nucleus: a 5'' cap is added, a poly-A tail is attached to the 3'' end, and non-coding sequences called introns are spliced out, leaving only the protein-coding exons to form the mature mRNA."},
    {"type": "callout", "style": "info", "title": "The Genetic Code", "content": "The mRNA sequence is read in three-nucleotide units called codons. Each of the 64 possible codons specifies either one of the 20 amino acids or a stop signal. The code is degenerate — multiple codons often specify the same amino acid — and nearly universal across all life forms, from bacteria in Saskatchewan soil to the largest mammals. AUG is the universal start codon, encoding methionine."},
    {"type": "heading", "level": 2, "text": "Translation: RNA to Protein"},
    {"type": "text", "content": "Translation occurs in the cytoplasm on ribosomes — large molecular machines made of ribosomal RNA (rRNA) and proteins. The ribosome binds to the 5'' end of the mRNA and moves along it codon by codon. Transfer RNA (tRNA) molecules act as adaptors, each carrying a specific amino acid and bearing an anticodon sequence complementary to the matching mRNA codon. When a tRNA''s anticodon pairs with the mRNA codon in the ribosome''s A site, the ribosome catalyses the formation of a peptide bond between the incoming amino acid and the growing polypeptide chain. The ribosome then translocates three nucleotides along the mRNA, and the process repeats. Translation ends when a stop codon (UAA, UAG, or UGA) enters the A site — no tRNA matches these codons, so a release factor binds instead, freeing the completed polypeptide."},
    {"type": "heading", "level": 2, "text": "Gene Regulation"},
    {"type": "text", "content": "Cells regulate gene expression at multiple levels. At the transcriptional level, regulatory proteins called transcription factors bind to enhancer or silencer sequences in the DNA and either stimulate or inhibit RNA polymerase. The lac operon in bacteria is a classic example: in the absence of lactose, a repressor protein blocks transcription of the enzymes needed to digest it. When lactose is present, it inactivates the repressor, allowing transcription to proceed. Post-transcriptional regulation includes control of mRNA stability, alternative splicing (which allows one gene to produce multiple protein isoforms), and RNA interference — in which small RNA molecules (siRNA and miRNA) trigger the degradation of specific mRNAs."},
    {"type": "heading", "level": 2, "text": "Epigenetics"},
    {"type": "text", "content": "Epigenetics refers to changes in gene expression that do not involve alterations to the DNA sequence itself. Two major mechanisms are DNA methylation — the addition of methyl groups to cytosine bases, which generally silences nearby genes — and histone modification, which alters how tightly DNA is wound around histone proteins. Tightly wound DNA (heterochromatin) is transcriptionally inactive; loosely wound DNA (euchromatin) is accessible to transcription factors. Epigenetic marks can be influenced by diet, stress, and environmental exposures, and some marks are transmitted to offspring. Research on Indigenous communities in Canada has highlighted how colonisation-related trauma and nutritional deprivation can produce epigenetic changes with multi-generational health consequences."},
    {"type": "callout", "style": "example", "title": "Worked Example: Transcription and Translation", "content": "Question: A DNA template strand reads 3''-TACGGATCC-5''. Determine (a) the mRNA sequence transcribed from it, and (b) the amino acid sequence translated from that mRNA.\n\n(a) Transcription — RNA polymerase reads 3'' to 5'' and builds mRNA 5'' to 3'':\n  DNA template: 3''-T A C G G A T C C-5''\n  mRNA:          5''-A U G C C U A G G-3''\n\n(b) Translation — divide mRNA into codons:\n  AUG = Methionine (start codon)\n  CCU = Proline\n  AGG = Arginine\n\nAnswer: The polypeptide begins Met-Pro-Arg. (In a real gene, additional codons would follow until a stop codon is reached.)"},
    {"type": "callout", "style": "tip", "title": "Indigenous Knowledge: Environmental Influence on Heredity", "content": "Cree and Métis knowledge systems recognise that the environment shapes organisms across generations — a concept that resonates with modern epigenetics. Traditional teachings describe how the conditions experienced by grandparents influence the vitality of grandchildren, particularly with respect to diet, relationship to the land, and emotional wellbeing. Contemporary epigenetic research is beginning to provide molecular explanations for these observations, showing that environmental stressors can alter gene expression patterns in ways that persist across multiple generations."},
    {"type": "quiz", "question": "During translation, which molecule reads the mRNA codon and delivers the corresponding amino acid?", "options": ["mRNA", "rRNA", "tRNA", "DNA polymerase"], "correctIndex": 2, "explanation": "Transfer RNA (tRNA) acts as the adaptor molecule in translation. Each tRNA has an anticodon that base-pairs with a specific mRNA codon, and it carries the corresponding amino acid to the ribosome where the peptide bond is formed."},
    {"type": "quiz", "question": "Which of the following is an example of post-transcriptional gene regulation?", "options": ["A transcription factor binding to an enhancer sequence", "RNA interference degrading a specific mRNA", "Methylation of a cytosine base in the DNA promoter", "Helicase unwinding DNA before transcription"], "correctIndex": 1, "explanation": "RNA interference (RNAi) occurs after transcription: small RNA molecules (siRNA or miRNA) bind to complementary mRNA sequences and trigger their degradation, preventing translation. The other options describe transcriptional or epigenetic regulation, or a step in replication."}
  ]'::jsonb,
  '[
    {"term": "Transcription", "definition": "The synthesis of an RNA molecule from a DNA template by RNA polymerase, transferring genetic information from DNA to mRNA."},
    {"term": "Translation", "definition": "The ribosome-mediated process of reading an mRNA sequence codon by codon to assemble a polypeptide chain."},
    {"term": "Codon", "definition": "A three-nucleotide sequence in mRNA that specifies a particular amino acid or a stop signal during translation."},
    {"term": "tRNA (Transfer RNA)", "definition": "An RNA molecule that carries a specific amino acid to the ribosome and has an anticodon that base-pairs with the corresponding mRNA codon."},
    {"term": "Promoter", "definition": "A DNA sequence upstream of a gene where RNA polymerase binds to initiate transcription."},
    {"term": "Intron", "definition": "A non-coding intervening sequence within a eukaryotic gene that is transcribed into pre-mRNA but removed by splicing before translation."},
    {"term": "Exon", "definition": "A coding sequence in a eukaryotic gene that remains in the mature mRNA after splicing and is translated into protein."},
    {"term": "Epigenetics", "definition": "Heritable changes in gene expression that do not involve changes to the DNA nucleotide sequence, often mediated by DNA methylation or histone modification."},
    {"term": "RNA Interference (RNAi)", "definition": "A post-transcriptional regulatory mechanism in which small RNA molecules silence gene expression by triggering the degradation of complementary mRNA."}
  ]'::jsonb,
  'Cree and Métis knowledge systems recognise that environmental conditions experienced by ancestors shape the vitality of descendants — an insight now supported by epigenetic research showing that stress and nutritional deprivation can alter gene expression patterns across generations.',
  40, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 6: Molecular Genetics & Biotechnology
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 6, 'Molecular Genetics & Biotechnology', 'molecular-genetics-and-biotechnology',
  'How scientists use PCR, gel electrophoresis, CRISPR, and genetic engineering to study and manipulate DNA, along with the ethical questions these powerful tools raise.',
  '[
    {"type": "heading", "level": 1, "text": "Molecular Genetics & Biotechnology"},
    {"type": "text", "content": "The ability to read, copy, cut, and rewrite DNA sequences has transformed medicine, agriculture, forensics, and environmental science. Saskatchewan sits at the intersection of many of these advances: from canola varieties engineered for herbicide tolerance to uranium mining that uses bacterial bioremediation, molecular biotechnology shapes the province''s economy and environment. In this chapter we examine the core tools of molecular genetics and the profound ethical questions they raise."},
    {"type": "heading", "level": 2, "text": "Polymerase Chain Reaction (PCR)"},
    {"type": "text", "content": "PCR is a technique for amplifying a specific DNA sequence — producing millions of copies of a target region from a tiny starting sample. The reaction requires the target DNA, two short primers (complementary to sequences flanking the target), a heat-stable DNA polymerase (typically Taq polymerase, isolated from a bacterium living in hot springs), and free nucleotides. PCR proceeds through repeated cycles of three temperatures: denaturation (~95 °C separates the strands), annealing (~55–65 °C allows primers to bind), and extension (~72 °C, at which Taq polymerase synthesises new DNA). Each cycle doubles the number of target copies, so 30 cycles can theoretically amplify a single copy more than one billion times. PCR is used in forensic DNA analysis, pathogen detection (including COVID-19 tests), paternity testing, and archaeological studies of ancient DNA."},
    {"type": "callout", "style": "info", "title": "Gel Electrophoresis", "content": "After amplifying DNA by PCR, scientists often need to separate fragments by size. Gel electrophoresis loads DNA samples into wells in an agarose gel, then applies an electric current. Because DNA is negatively charged, fragments migrate toward the positive electrode. Smaller fragments travel faster and farther through the gel''s pores than larger ones. Under UV light, DNA stained with a fluorescent dye appears as distinct bands that can be compared with a DNA ladder (a standard mixture of fragments of known sizes) to determine fragment lengths."},
    {"type": "heading", "level": 2, "text": "Recombinant DNA and Genetic Engineering"},
    {"type": "text", "content": "Recombinant DNA technology involves cutting DNA from two different sources and joining the fragments together. Restriction enzymes — molecular scissors that cut DNA at specific recognition sequences — allow scientists to cut both the gene of interest and a vector (typically a plasmid or virus) at the same sites. The fragments are joined by DNA ligase, creating recombinant DNA. When this recombinant plasmid is introduced into a host cell (transformation), the cell replicates the foreign gene along with its own DNA. Genetically modified organisms (GMOs) produced by this approach include insulin-producing bacteria (eliminating the need to extract insulin from pig pancreases), Bt crops that produce insecticidal proteins, and golden rice engineered to produce beta-carotene. Saskatchewan is one of Canada''s largest producers of GMO canola, designed to tolerate specific herbicides, simplifying weed management for farmers."},
    {"type": "heading", "level": 2, "text": "CRISPR-Cas9"},
    {"type": "text", "content": "CRISPR-Cas9 is a revolutionary gene-editing tool adapted from a natural defence system found in bacteria. The system uses a guide RNA to direct the Cas9 protein to a specific DNA sequence, where it makes a precise double-strand cut. The cell''s own DNA repair machinery then either disrupts the gene (via error-prone repair) or inserts a new sequence (via a supplied template). Compared with earlier gene-editing tools, CRISPR is faster, cheaper, and more precise. It is being developed to treat genetic disorders such as sickle-cell disease, engineer crops resistant to drought and disease, and even attempt to resurrect extinct species. In 2023, the first CRISPR-based therapy for sickle-cell disease received regulatory approval in the United States — a milestone that heralded a new era of molecular medicine."},
    {"type": "callout", "style": "example", "title": "Worked Example: Restriction Enzyme Mapping", "content": "Question: A circular plasmid (4 000 bp) is cut with restriction enzyme EcoRI, which recognises the sequence GAATTC and cuts between G and AATTC. The digest produces fragments of 1 200 bp, 1 800 bp, and 1 000 bp. How many EcoRI recognition sites does the plasmid contain?\n\nStep 1: A circular DNA molecule cut at n sites produces n linear fragments.\nStep 2: The digest yields 3 fragments (1 200 + 1 800 + 1 000 = 4 000 bp — consistent with the plasmid size).\n\nAnswer: The plasmid contains 3 EcoRI recognition sites."},
    {"type": "heading", "level": 2, "text": "Ethics of Biotechnology"},
    {"type": "text", "content": "Biotechnology raises questions that go far beyond the laboratory. Who owns a patented gene or engineered organism? Should gene editing in human embryos be permitted? How do we ensure equitable access to gene therapies that may cost millions of dollars? For Indigenous communities, concerns include bioprospecting — the commercialisation of traditional knowledge or biological resources without consent or benefit-sharing. The United Nations Declaration on the Rights of Indigenous Peoples (UNDRIP) affirms Indigenous Peoples'' rights over their genetic resources, seeds, and traditional knowledge. In Saskatchewan, First Nations communities have raised concerns about GMO crops cross-pollinating traditional varieties and about the patenting of wild berry and medicinal plant genetics without consultation. These are not hypothetical concerns — they require ongoing, respectful dialogue between scientists, governments, corporations, and Indigenous knowledge holders."},
    {"type": "callout", "style": "tip", "title": "Indigenous Knowledge: Bioprospecting and Sovereignty", "content": "Several pharmaceutical and agricultural companies have sought patents on compounds or varieties derived from plants used in Indigenous medicine and agriculture for centuries. Cree, Nakoda, and Dene communities in Saskatchewan and across Canada are actively asserting their rights under UNDRIP to control how their traditional knowledge and biological resources are studied and commercialised. The principle of free, prior, and informed consent (FPIC) requires that any research involving Indigenous genetic resources or knowledge be conducted only with the explicit agreement of the community involved — a standard that the broader scientific community is working to uphold."},
    {"type": "quiz", "question": "In PCR, why is Taq polymerase used instead of a standard DNA polymerase?", "options": ["It is cheaper to produce", "It remains functional at the high temperatures used in the denaturation step", "It does not require primers to begin synthesis", "It can amplify both DNA and RNA simultaneously"], "correctIndex": 1, "explanation": "The denaturation step in PCR requires heating the reaction to about 95 °C, which would denature and inactivate most DNA polymerases. Taq polymerase, isolated from the thermophilic bacterium Thermus aquaticus, retains its enzymatic activity at these high temperatures."},
    {"type": "quiz", "question": "What is the role of a guide RNA in the CRISPR-Cas9 system?", "options": ["It codes for the Cas9 protein", "It repairs the DNA double-strand break", "It directs the Cas9 enzyme to the specific target DNA sequence", "It amplifies the edited gene after cutting"], "correctIndex": 2, "explanation": "The guide RNA (gRNA) is a short RNA molecule designed to be complementary to the target DNA sequence. It forms a complex with the Cas9 protein and base-pairs with the target site, positioning Cas9 to make a precise cut in the DNA."}
  ]'::jsonb,
  '[
    {"term": "PCR (Polymerase Chain Reaction)", "definition": "A technique that amplifies a specific DNA sequence through repeated cycles of denaturation, primer annealing, and extension by heat-stable DNA polymerase."},
    {"term": "Gel Electrophoresis", "definition": "A laboratory method that separates DNA, RNA, or protein fragments by size using an electric current through an agarose or polyacrylamide gel."},
    {"term": "Restriction Enzyme", "definition": "An enzyme that cuts double-stranded DNA at a specific recognition sequence, used in recombinant DNA technology to isolate and join gene fragments."},
    {"term": "Recombinant DNA", "definition": "DNA produced by joining sequences from two different sources, typically a gene of interest inserted into a plasmid vector."},
    {"term": "Plasmid", "definition": "A small, circular, double-stranded DNA molecule found in bacteria that can replicate independently and is used as a vector in genetic engineering."},
    {"term": "CRISPR-Cas9", "definition": "A precise gene-editing tool that uses a guide RNA to direct the Cas9 endonuclease to a specific genomic location, where it makes a targeted double-strand cut."},
    {"term": "GMO (Genetically Modified Organism)", "definition": "An organism whose genome has been altered using recombinant DNA technology to introduce, remove, or modify specific traits."},
    {"term": "Bioprospecting", "definition": "The search for commercially valuable biological materials or traditional knowledge, raising ethical concerns about consent and benefit-sharing with source communities."},
    {"term": "Transformation", "definition": "The uptake and incorporation of foreign DNA by a bacterial cell, used to introduce recombinant plasmids into host cells in genetic engineering."}
  ]'::jsonb,
  'Cree, Nakoda, and Dene communities in Saskatchewan are actively asserting rights under UNDRIP to control how their traditional biological knowledge and plant varieties are studied and commercialised, requiring free, prior, and informed consent for any research on Indigenous genetic resources.',
  42, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 7: Population Ecology
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 7, 'Population Ecology', 'population-ecology',
  'Mathematical models and real-world factors that govern how populations grow, stabilise, and decline, with Saskatchewan examples from bison recovery to grassland songbird surveys.',
  '[
    {"type": "heading", "level": 1, "text": "Population Ecology"},
    {"type": "text", "content": "A population is a group of individuals of the same species living in the same area at the same time. Population ecology examines how and why population size changes over time — knowledge that is essential for managing fisheries, controlling invasive species, planning conservation efforts, and predicting the spread of infectious diseases. Saskatchewan''s landscapes provide vivid case studies: the near-extinction and partial recovery of plains bison, the dramatic swings in snowshoe hare and lynx numbers in the boreal forest, and the ongoing decline of grassland-nesting songbirds such as the Sprague''s pipit."},
    {"type": "heading", "level": 2, "text": "Describing Populations"},
    {"type": "text", "content": "Ecologists characterise populations using several key metrics. Population size (N) is the total number of individuals. Population density is the number of individuals per unit area or volume. Dispersion describes how individuals are distributed in space: uniform dispersion (e.g., trees competing for light), random dispersion (e.g., dandelions in a field), or clumped dispersion (e.g., bison in herds, fish in schools). Demography is the statistical study of population structure — the proportions of individuals in different age classes — which is captured in a life table or age structure diagram. A population with many young individuals is likely to grow; one skewed toward older individuals may be declining."},
    {"type": "callout", "style": "info", "title": "Mark-Recapture Method", "content": "Estimating the size of a wild population directly is rarely feasible. The mark-recapture (Lincoln-Petersen) method provides an estimate by capturing and marking a sample of individuals (M), releasing them, then later recapturing a second sample (n) and counting the marked individuals in it (m). Population estimate N ≈ (M × n) / m. This technique is widely used for Saskatchewan waterfowl surveys and fisheries assessments."},
    {"type": "heading", "level": 2, "text": "Population Growth Models"},
    {"type": "text", "content": "The simplest model of population growth assumes unlimited resources. Under these conditions, a population grows exponentially: Nt = N₀ × e^(rt), where N₀ is the initial size, r is the intrinsic rate of natural increase, and t is time. Exponential growth produces a characteristic J-shaped curve. However, real populations face resource limitations. The logistic growth model incorporates carrying capacity (K) — the maximum population size the environment can sustainably support. As population size approaches K, growth slows and the curve becomes S-shaped (sigmoidal). The logistic equation is: dN/dt = rN × (K − N)/K. When N is small, (K − N)/K ≈ 1 and growth is nearly exponential; when N approaches K, the fraction approaches zero and growth stalls."},
    {"type": "heading", "level": 2, "text": "Factors Limiting Population Growth"},
    {"type": "text", "content": "Population growth is regulated by density-dependent and density-independent factors. Density-dependent factors — competition for food or territory, predation, disease, and parasitism — become more intense as population density increases, providing negative feedback that drives populations toward K. Density-independent factors — severe weather, drought, wildfire, and floods — affect populations regardless of their size. Saskatchewan''s periodic drought cycles have dramatic density-independent effects on grassland species. In 1988, a severe drought dried up most prairie potholes, collapsing duck nesting habitat across the province and reducing populations of mallards, pintails, and teals by millions of birds — a vivid illustration of how climatic events can override density-dependent regulation."},
    {"type": "heading", "level": 2, "text": "Life History Strategies"},
    {"type": "text", "content": "Different species have evolved contrasting life history strategies that reflect trade-offs between reproduction and survival. r-selected species (like mice, dandelions, and mosquitoes) invest little in each offspring but produce vast numbers, enabling rapid colonisation of disturbed habitats. K-selected species (like bison, whooping cranes, and beluga whales) produce few offspring but invest heavily in their survival, resulting in low reproductive rates but long lifespans. Prairie species in Saskatchewan span this spectrum: Richardson''s ground squirrels are relatively r-selected, while bison and sharp-tailed grouse are more K-selected — a distinction that matters enormously when designing recovery programs for species at risk."},
    {"type": "callout", "style": "example", "title": "Worked Example: Mark-Recapture", "content": "Question: Biologists studying northern pike in Waskesiu Lake capture and tag 200 fish (M = 200), then release them. Two weeks later they capture a new sample of 150 fish (n = 150), of which 30 are tagged (m = 30). Estimate the population size.\n\nUsing the Lincoln-Petersen formula: N ≈ (M × n) / m\nN ≈ (200 × 150) / 30 = 30 000 / 30 = 1 000\n\nAnswer: The estimated northern pike population in the lake is approximately 1 000 individuals. (Assumptions include that the population is closed, marking does not affect survival, and tagged fish mix randomly with the population before the second capture.)"},
    {"type": "callout", "style": "tip", "title": "Indigenous Knowledge: Bison and Ecological Indicators", "content": "Plains Cree, Blackfoot, and Nakoda Peoples maintained detailed knowledge of bison population dynamics across the prairies. Hunters monitored indicators such as herd size, body condition, forage quality, and movement patterns to determine sustainable harvest levels — practices that effectively managed what we now recognise as a complex K-selected species approaching carrying capacity in certain ranges. The near-extinction of bison by the 1880s through commercial hunting, combined with deliberate government policy, devastated these knowledge systems along with the herds themselves. Contemporary bison restoration projects on First Nations lands, such as the re-wilding of bison at Wanuskewin Heritage Park near Saskatoon, are reconnecting Indigenous ecological knowledge with conservation science."},
    {"type": "quiz", "question": "A population grows according to the logistic model with K = 500 and current N = 500. What is the population''s growth rate?", "options": ["Maximum", "Slightly positive", "Zero", "Negative"], "correctIndex": 2, "explanation": "In the logistic model, dN/dt = rN(K − N)/K. When N = K, the term (K − N) = (500 − 500) = 0, so the entire expression equals zero. The population is at carrying capacity and, in the absence of other factors, neither grows nor declines."},
    {"type": "quiz", "question": "Which of the following is a density-INDEPENDENT factor limiting population growth?", "options": ["Competition for nesting sites", "Predation by a specialist predator", "A late-spring blizzard that kills nesting birds", "Parasitism by a host-specific pathogen"], "correctIndex": 2, "explanation": "A late-spring blizzard kills birds regardless of how many are present — its impact does not change with population density. The other options — competition, specialist predation, and host-specific parasitism — all intensify as population density increases, making them density-dependent factors."}
  ]'::jsonb,
  '[
    {"term": "Population", "definition": "A group of individuals of the same species inhabiting the same geographic area at the same time."},
    {"term": "Carrying Capacity (K)", "definition": "The maximum population size that a given environment can sustain indefinitely, given available resources."},
    {"term": "Exponential Growth", "definition": "Population growth that occurs at a constant per-capita rate, producing a J-shaped curve when population size is plotted against time."},
    {"term": "Logistic Growth", "definition": "Population growth that slows as the population approaches carrying capacity, producing an S-shaped (sigmoidal) curve."},
    {"term": "Density-Dependent Factor", "definition": "A population-regulating factor whose effect intensifies as population density increases, such as competition, predation, or disease."},
    {"term": "Density-Independent Factor", "definition": "A factor that affects population size regardless of density, such as drought, blizzard, or wildfire."},
    {"term": "Mark-Recapture", "definition": "A method for estimating population size by marking and releasing a sample, then capturing a second sample and calculating the proportion marked."},
    {"term": "r-selected Species", "definition": "A species characterised by high reproductive rate, many small offspring, and rapid population growth — adapted for unstable or newly available habitats."},
    {"term": "K-selected Species", "definition": "A species characterised by low reproductive rate, few large offspring, and high parental investment — adapted for stable environments near carrying capacity."},
    {"term": "Demography", "definition": "The statistical study of populations, including age structure, birth rates, death rates, and migration patterns."}
  ]'::jsonb,
  'Plains Cree, Blackfoot, and Nakoda Peoples maintained sophisticated knowledge of bison population dynamics, effectively managing sustainable harvest from K-selected herds. Contemporary bison re-wilding on First Nations lands — such as at Wanuskewin Heritage Park near Saskatoon — reconnects Indigenous ecological knowledge with modern conservation science.',
  40, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 8: Community Ecology & Biodiversity
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 8, 'Community Ecology & Biodiversity', 'community-ecology-and-biodiversity',
  'How species interact within ecological communities through competition, predation, mutualism, and parasitism; how communities change through succession; and why biodiversity matters for ecosystem resilience.',
  '[
    {"type": "heading", "level": 1, "text": "Community Ecology & Biodiversity"},
    {"type": "text", "content": "An ecological community is the assemblage of all species — plants, animals, fungi, and microorganisms — living in a defined area and interacting with one another. The structure of a community emerges from thousands of simultaneous species interactions: a wolf pack hunting elk, bacteria fixing nitrogen in prairie soil, mycorrhizal fungi trading phosphorus for sugar with aspen roots. Understanding these interactions — and how communities change over time — is central to conserving Saskatchewan''s remarkable biological diversity, from its alkali wetlands to its ancient boreal shields."},
    {"type": "heading", "level": 2, "text": "Species Interactions"},
    {"type": "text", "content": "Ecologists classify species interactions by their effect on each participant. Competition (−/−) occurs when two species use the same limiting resource; the competitive exclusion principle states that two species with identical ecological niches cannot coexist indefinitely — one will displace the other unless the species differentiate their niches (resource partitioning). Predation (+/−) includes all cases where one organism consumes another: carnivory, herbivory, and parasitism are all forms of predation in this broad sense. Mutualism (+/+) benefits both parties — mycorrhizal fungi and plant roots are a prime example, with the fungus receiving sugars and the plant gaining phosphorus and water. Commensalism (+/0) benefits one partner without noticeably affecting the other, such as cattle egrets following bison to catch insects flushed from the grass."},
    {"type": "callout", "style": "info", "title": "Keystone Species", "content": "A keystone species has a disproportionately large effect on its community relative to its abundance. Remove a keystone species and the community changes dramatically. Wolves in Yellowstone — and historically across the northern prairies — exemplify a keystone predator: by controlling elk numbers and behaviour, wolves indirectly protect riparian vegetation, which in turn provides habitat for songbirds, beavers, and fish. This cascade of indirect effects is called a trophic cascade."},
    {"type": "heading", "level": 2, "text": "Ecological Succession"},
    {"type": "text", "content": "Ecological succession is the predictable, directional change in a community''s species composition over time. Primary succession begins on bare substrate with no soil — such as the granite outcrops exposed after glacial retreat across the Canadian Shield north of Saskatchewan''s boreal forest. Pioneer species (lichens, mosses) colonise first, breaking down rock and accumulating organic matter. As soil deepens, shrubs and then trees establish, gradually transitioning to a mature forest community. Secondary succession occurs after a disturbance removes the existing community but leaves the soil intact — for example, the re-vegetation of a burned prairie or an abandoned farm field. Grasslands often return quickly to fields in southern Saskatchewan, while boreal forests may take a century or more to recover their full complexity after fire."},
    {"type": "heading", "level": 2, "text": "Biodiversity and Ecosystem Function"},
    {"type": "text", "content": "Biodiversity encompasses genetic diversity within species, species diversity within communities, and ecosystem diversity across a landscape. High species diversity generally improves ecosystem stability and productivity through complementarity (different species use resources differently, reducing waste) and the portfolio effect (a diverse community is less vulnerable to a single stressor). The biodiversity of Saskatchewan''s native grasslands — encompassing hundreds of plant species, thousands of invertebrates, and dozens of vertebrates — underpins ecosystem services worth billions of dollars annually: forage for livestock, carbon sequestration, water filtration, pollination, and cultural significance. Less than 20 percent of the province''s native mixed-grass prairie remains intact, making it one of Canada''s most threatened ecosystems."},
    {"type": "callout", "style": "example", "title": "Worked Example: Competitive Exclusion vs. Coexistence", "content": "Question: Two species of ground squirrel both eat seeds and live in southern Saskatchewan. After 10 years of observation, both species persist in the same fields. Does this violate the competitive exclusion principle?\n\nAnalysis: The competitive exclusion principle predicts that two species with identical niches cannot coexist. Persistent coexistence suggests the species have partitioned their niches.\n\nInvestigation: Detailed study reveals that Species A preferentially forages beneath shrub cover while Species B forages in open grassland. They consume somewhat different seed sizes and are active at slightly different times of day.\n\nConclusion: Resource partitioning allows coexistence. Their niches are similar but not identical, so neither excludes the other. This is consistent with, not a violation of, the competitive exclusion principle."},
    {"type": "callout", "style": "tip", "title": "Indigenous Knowledge: Land Management for Biodiversity", "content": "Plains Cree, Assiniboine, and Blackfoot Peoples managed prairie biodiversity through deliberate burning, selective harvesting, and protection of critical habitats such as river crossings and berry patches. Controlled burns maintained a mosaic of grassland ages and structures, supporting a far greater diversity of plant and animal species than fire-suppressed monocultures. Contemporary range ecologists have confirmed that rotational grazing and patch burning — practices mirroring traditional land management — produce higher plant and pollinator diversity than continuous grazing or fire exclusion. Several First Nations in Saskatchewan are reviving prescribed burning programs in collaboration with provincial land managers to restore grassland biodiversity."},
    {"type": "quiz", "question": "The presence of wolves in a national park leads to reduced elk grazing along riverbanks, allowing willows and aspens to recover, which in turn increases beaver populations and improves fish habitat. This sequence of effects is an example of:", "options": ["Primary succession", "A trophic cascade", "Competitive exclusion", "Resource partitioning"], "correctIndex": 1, "explanation": "A trophic cascade occurs when a top predator (wolves) indirectly affects lower trophic levels by suppressing the abundance or behaviour of herbivores (elk), which in turn allows vegetation to recover, benefiting additional species (beavers, fish). This is a hallmark effect of keystone predators."},
    {"type": "quiz", "question": "A newly formed volcanic island is colonised first by lichens, then by mosses, then by grasses, and eventually by shrubs and trees. This process is called:", "options": ["Secondary succession", "Resource partitioning", "Primary succession", "Competitive exclusion"], "correctIndex": 2, "explanation": "Primary succession begins on bare substrate with no pre-existing soil or organic matter. Pioneer species (like lichens) slowly modify the substrate, creating conditions that allow other species to establish in a predictable sequence over time."}
  ]'::jsonb,
  '[
    {"term": "Ecological Community", "definition": "The assemblage of all populations of different species living and interacting in a defined area."},
    {"term": "Competitive Exclusion Principle", "definition": "The concept that two species with identical ecological niches cannot coexist indefinitely — one will outcompete and displace the other."},
    {"term": "Resource Partitioning", "definition": "The division of a shared resource among species that reduces direct competition, allowing ecologically similar species to coexist."},
    {"term": "Keystone Species", "definition": "A species that has a disproportionately large effect on its community relative to its abundance; its removal causes major shifts in community structure."},
    {"term": "Trophic Cascade", "definition": "Indirect effects of a top predator on lower trophic levels, transmitted through changes in herbivore abundance or behaviour."},
    {"term": "Primary Succession", "definition": "Ecological succession that begins on bare substrate lacking soil, such as newly exposed rock or volcanic lava fields."},
    {"term": "Secondary Succession", "definition": "Ecological succession in an area where a community previously existed but was disturbed, leaving soil intact."},
    {"term": "Mutualism", "definition": "A species interaction in which both participants benefit, such as the relationship between mycorrhizal fungi and plant roots."},
    {"term": "Biodiversity", "definition": "The variety of life at all levels: genetic diversity within species, species diversity within communities, and ecosystem diversity across landscapes."}
  ]'::jsonb,
  'Plains Cree, Assiniboine, and Blackfoot Peoples used controlled burning and selective harvesting to maintain prairie biodiversity — practices that contemporary range ecologists confirm produce higher plant and pollinator diversity. First Nations in Saskatchewan are reviving prescribed burning programs in collaboration with provincial land managers.',
  38, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 9: Evolution — Evidence & Mechanisms
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 9, 'Evolution: Evidence & Mechanisms', 'evolution-evidence-and-mechanisms',
  'The evidence for biological evolution drawn from fossils, comparative anatomy, and molecular biology, alongside the mechanisms — natural selection, genetic drift, and gene flow — that drive evolutionary change.',
  '[
    {"type": "heading", "level": 1, "text": "Evolution: Evidence & Mechanisms"},
    {"type": "text", "content": "Biological evolution — descent with modification from common ancestors — is the unifying framework of modern biology. It explains why organisms are adapted to their environments, why fossils document creatures no longer alive today, why all life shares a common genetic code, and why pathogens can evolve resistance to our medicines. The evidence for evolution is vast and mutually reinforcing, drawn from palaeontology, comparative anatomy, embryology, biogeography, and molecular biology. In Saskatchewan, the Frenchman River Valley in the southwest contains some of the world''s richest dinosaur fossil beds, providing direct evidence of life''s long and changing history."},
    {"type": "heading", "level": 2, "text": "Evidence for Evolution"},
    {"type": "text", "content": "The fossil record documents a succession of life forms through geological time, with older strata containing organisms more distantly related to modern species. Transitional fossils — organisms with features intermediate between ancestral and derived groups — are particularly informative. Comparative anatomy reveals homologous structures: the forelimbs of humans, horses, bats, and whales share the same underlying bone arrangement (humerus, radius, ulna, carpals, phalanges), indicating common ancestry despite vastly different functions. Vestigial structures — such as the remnant pelvic bones in snakes and whales — are evolutionary remnants of features that were functional in ancestors. Molecular evidence is perhaps the most powerful: the greater the similarity in DNA or protein sequences between two species, the more recently they shared a common ancestor. Phylogenetic trees built from molecular data closely match those built from morphological evidence."},
    {"type": "heading", "level": 2, "text": "Natural Selection"},
    {"type": "text", "content": "Natural selection, first described by Charles Darwin and Alfred Russel Wallace in 1858, is the primary mechanism driving adaptive evolution. It requires four conditions: heritable variation (individuals vary in traits, and those traits are inherited); differential survival and reproduction (some variants survive and reproduce better than others in the current environment); non-random selection (survival and reproduction are not random but depend on the variant''s characteristics). Over generations, allele frequencies shift and populations become better adapted. Natural selection can favour intermediate phenotypes (stabilising selection), extreme phenotypes at one end (directional selection), or both extremes simultaneously (disruptive selection). Antibiotic resistance in bacteria is a rapid, observable example of directional selection: bacteria with resistance alleles survive antibiotic exposure and pass resistance genes to offspring."},
    {"type": "callout", "style": "info", "title": "Genetic Drift", "content": "In small populations, random chance can cause allele frequencies to change in ways unrelated to fitness — a process called genetic drift. Two special cases are the bottleneck effect (a dramatic reduction in population size, as nearly occurred with plains bison) and the founder effect (a small group colonising a new area carries only a subset of the original population''s alleles). Genetic drift reduces genetic diversity and can fix harmful alleles by chance, making small populations more vulnerable to extinction."},
    {"type": "heading", "level": 2, "text": "Speciation"},
    {"type": "text", "content": "Speciation — the formation of new species — occurs when populations become reproductively isolated and diverge genetically over time. Allopatric speciation occurs when a geographic barrier (a mountain range, a river, an expanding ice sheet) separates a population into two groups that evolve independently. Sympatric speciation occurs without geographic separation, often through polyploidy (especially in plants) or through disruptive selection. The diverse array of grassland and boreal bird species across Saskatchewan''s ecological gradient reflects allopatric speciation events driven by Pleistocene glacial cycles that repeatedly fragmented and reconnected populations across North America."},
    {"type": "heading", "level": 2, "text": "Phylogenetics and the Tree of Life"},
    {"type": "text", "content": "A phylogenetic tree (or phylogeny) is a branching diagram that represents evolutionary relationships among organisms or genes. Clades are groups of organisms that include an ancestor and all of its descendants. Cladistics constructs phylogenies based on shared derived characters — features present in a common ancestor and all of its descendants but not in more distant relatives. Molecular phylogenetics uses DNA and protein sequence comparisons to build these trees, enabling researchers to date divergence events using molecular clocks (the relatively constant rate at which neutral mutations accumulate). These tools are revolutionising our understanding of microbial diversity, the origin of major animal groups, and the evolutionary history of economically important species like canola''s Brassica ancestors."},
    {"type": "callout", "style": "example", "title": "Worked Example: Hardy-Weinberg Equilibrium", "content": "Question: In a population of pocket gophers, the frequency of a recessive burrowing-efficiency allele (a) is 0.3. Assuming Hardy-Weinberg equilibrium, what fraction of the population is expected to be heterozygous (Aa)?\n\nStep 1: p + q = 1, where p = frequency of A and q = frequency of a.\n  q = 0.3, so p = 1 − 0.3 = 0.7.\n\nStep 2: Hardy-Weinberg predicts genotype frequencies:\n  AA = p² = (0.7)² = 0.49\n  Aa = 2pq = 2(0.7)(0.3) = 0.42\n  aa = q² = (0.3)² = 0.09\n\nAnswer: 42% of the population is expected to be heterozygous. Hardy-Weinberg equilibrium is a null model; departures from these expected frequencies indicate that evolution is occurring."},
    {"type": "callout", "style": "tip", "title": "Indigenous Knowledge: Change, Relationships, and Deep Time", "content": "Many Indigenous knowledge systems across the northern plains articulate a view of life as fundamentally relational and continuously changing — a perspective that resonates with evolutionary biology''s emphasis on descent, adaptation, and the interconnectedness of all organisms. Cree oral traditions describe transformations of the landscape and its inhabitants over vast spans of time, including memories of different climate conditions and animal assemblages that align with palaeontological evidence of post-glacial change in Saskatchewan. Collaborations between Indigenous oral historians and palaeontologists in the Frenchman River region have enriched scientific understanding of the end-Cretaceous extinction event and post-glacial ecosystem recovery."},
    {"type": "quiz", "question": "Which observation provides the strongest molecular evidence that humans and chimpanzees share a recent common ancestor?", "options": ["Both organisms are bilaterally symmetrical", "Their DNA sequences are approximately 98–99% identical", "Both species practice social grooming", "Both species have vestigial tail structures during embryonic development"], "correctIndex": 1, "explanation": "Molecular evidence from DNA sequence comparisons is among the most powerful evidence for evolutionary relationships. Humans and chimpanzees share approximately 98–99% DNA sequence identity, indicating a very recent divergence (~6 million years ago) from a common ancestor. Greater sequence similarity corresponds to more recent common ancestry."},
    {"type": "quiz", "question": "A population of Arctic foxes experiences a severe disease outbreak that reduces the population from 10 000 to 80 individuals. The survivors happen to carry a high frequency of a neutral coat-colour allele rare in the original population. This scenario describes:", "options": ["Natural selection acting on coat colour", "The bottleneck effect and genetic drift", "The founder effect and gene flow", "Disruptive selection and sympatric speciation"], "correctIndex": 1, "explanation": "A dramatic reduction in population size due to a random event (disease outbreak) — not selection based on coat colour — is a textbook bottleneck effect. The shift in allele frequency among survivors is due to genetic drift, not natural selection, because the coat-colour allele is described as neutral."}
  ]'::jsonb,
  '[
    {"term": "Natural Selection", "definition": "The mechanism of evolution in which individuals with heritable traits better suited to the environment survive and reproduce more successfully, shifting allele frequencies over generations."},
    {"term": "Genetic Drift", "definition": "Random changes in allele frequency in a population due to chance events, most pronounced in small populations."},
    {"term": "Bottleneck Effect", "definition": "A reduction in genetic diversity that occurs when a population is drastically reduced in size by a random event, leaving survivors with a non-representative sample of the original gene pool."},
    {"term": "Speciation", "definition": "The evolutionary process by which new biological species arise through reproductive isolation and genetic divergence."},
    {"term": "Allopatric Speciation", "definition": "Speciation driven by geographic separation, which prevents gene flow and allows isolated populations to diverge independently."},
    {"term": "Phylogenetics", "definition": "The study of evolutionary relationships among organisms, typically represented as branching phylogenetic trees built from morphological or molecular data."},
    {"term": "Homologous Structure", "definition": "An anatomical feature shared by different species due to inheritance from a common ancestor, even if the structures now serve different functions."},
    {"term": "Vestigial Structure", "definition": "A reduced or non-functional structure that was functional in an ancestral species, serving as evidence of evolutionary history."},
    {"term": "Hardy-Weinberg Equilibrium", "definition": "A null model predicting that allele and genotype frequencies remain constant across generations in a large population free from mutation, selection, genetic drift, gene flow, and non-random mating."}
  ]'::jsonb,
  'Cree oral traditions describe landscape and faunal transformations over vast spans of time that align with palaeontological evidence. Collaborations between Indigenous oral historians and palaeontologists in Saskatchewan''s Frenchman River region have enriched scientific understanding of post-glacial ecosystem recovery.',
  42, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 10: Human Impact & Conservation
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 10, 'Human Impact & Conservation', 'human-impact-and-conservation',
  'How habitat loss, overexploitation, invasive species, and climate change threaten biodiversity, and what conservation strategies — including Indigenous-led stewardship — can protect ecosystems for future generations.',
  '[
    {"type": "heading", "level": 1, "text": "Human Impact & Conservation"},
    {"type": "text", "content": "Humans are now the dominant force shaping Earth''s biosphere. The current rate of species extinction is estimated to be 100 to 1 000 times higher than the natural background rate — a loss of biological diversity unprecedented since the mass extinction that ended the Cretaceous period 66 million years ago. In Saskatchewan, centuries of agricultural conversion, urban development, wetland drainage, and resource extraction have transformed landscapes and threatened hundreds of species. At the same time, conservation biology — a discipline that integrates ecology, genetics, and social science — is providing tools to slow and even reverse these losses, particularly when guided by Indigenous stewardship knowledge."},
    {"type": "heading", "level": 2, "text": "Habitat Loss and Fragmentation"},
    {"type": "text", "content": "Habitat loss is the primary driver of species decline globally. In Saskatchewan, the conversion of native mixed-grass and fescue prairie to cropland has left less than 20 percent of the original grassland ecosystem intact. Habitat fragmentation divides remaining natural areas into isolated patches, reducing their effective size, increasing edge effects (altered conditions at habitat boundaries), and preventing dispersal between populations. Small, isolated populations are more vulnerable to inbreeding and genetic drift, reducing their adaptive potential. Restoration ecology seeks to reconnect fragmented habitats through wildlife corridors — strips of native habitat linking larger patches — allowing animals to move, disperse, and maintain genetic diversity."},
    {"type": "heading", "level": 2, "text": "Overexploitation and Invasive Species"},
    {"type": "text", "content": "Overexploitation — harvesting organisms faster than they can reproduce — has driven numerous species to extinction or near-extinction. Saskatchewan''s commercial fisheries must balance economic harvest against long-term population sustainability. Invasive species pose a growing threat: organisms introduced outside their natural range often lack local predators, parasites, or competitors, enabling explosive population growth that displaces native species. Carp introduced to Saskatchewan lakes uproot aquatic vegetation and increase water turbidity, degrading habitat for native fish and waterfowl. The emerald ash borer, now spreading through eastern and central Canada, threatens ash trees that provide critical habitat in river valley forests. Prevention — rigorous inspection and biosecurity at borders — is far more cost-effective than control or eradication once a species is established."},
    {"type": "callout", "style": "info", "title": "Climate Change and Saskatchewan Ecosystems", "content": "Saskatchewan is warming approximately twice as fast as the global average. Longer growing seasons and warmer temperatures benefit some species but stress others. Prairie potholes — the shallow, seasonal wetlands that serve as the breeding ground for 50–80% of North America''s ducks — are drying out as evaporation increases. Boreal forests face more frequent and severe wildfires. Permafrost thaw in the far north releases stored carbon, accelerating warming. Species must shift ranges poleward or to higher elevations, but fragmented landscapes may prevent dispersal. Climate change amplifies every other threat facing biodiversity."},
    {"type": "heading", "level": 2, "text": "Conservation Strategies"},
    {"type": "text", "content": "Conservation biology employs several complementary strategies. Protected areas — national parks, provincial parks, ecological reserves, and Indigenous Protected and Conserved Areas (IPCAs) — preserve habitat and reduce direct exploitation. In situ conservation maintains species in their natural habitats; ex situ conservation preserves genetic diversity outside the wild (seed banks, captive breeding programs). Population viability analysis (PVA) uses demographic and genetic data to estimate a minimum viable population (MVP) — the smallest population likely to persist for a defined time with a specified probability. Ecosystem-based management recognises that protecting individual species is insufficient without protecting the communities and processes they depend on. The Target 30 framework (30 percent of land and ocean protected by 2030) adopted by the federal government provides a national goal that aligns with international biodiversity commitments."},
    {"type": "callout", "style": "example", "title": "Worked Example: Island Biogeography Applied to Habitat Patches", "content": "Question: A nature reserve of 100 km² supports 80 bird species. A proposal would reduce the reserve to 10 km² (a 90% reduction in area). Using the species-area relationship S = cA^z (where z ≈ 0.25 for habitat islands), estimate the predicted number of species remaining.\n\nStep 1: Calculate the ratio of new to old area: A_new / A_old = 10 / 100 = 0.10\nStep 2: Apply the species-area relationship: S_new / S_old = (A_new / A_old)^z = (0.10)^0.25\nStep 3: (0.10)^0.25 = 10^(−0.25) ≈ 0.562\nStep 4: S_new = 80 × 0.562 ≈ 45 species\n\nAnswer: Reducing the reserve area by 90% is predicted to result in the loss of approximately 35 bird species — a 44% reduction in species richness. This illustrates why even partial habitat preservation is far better than none."},
    {"type": "callout", "style": "tip", "title": "Indigenous Knowledge: Guardians of the Land", "content": "Indigenous Protected and Conserved Areas (IPCAs) are lands and waters where Indigenous governments have the primary role in protecting and conserving ecosystems using a combination of Indigenous law, governance, and knowledge alongside Western science. In Saskatchewan, Woodland Cree, Dene, and Nêhiyaw (Plains Cree) communities are leading conservation efforts on their traditional territories — managing bison recovery, protecting old-growth boreal forest, restoring prairie wetlands, and reviving cultural burning practices. Research consistently shows that biodiversity outcomes on Indigenous-managed lands are equal to or better than those on government-managed protected areas. Recognising Indigenous land rights and governance authority is therefore not only a matter of justice but also a cornerstone of effective conservation biology."},
    {"type": "quiz", "question": "Which threat to biodiversity is considered the most significant globally?", "options": ["Invasive species", "Climate change", "Habitat loss and fragmentation", "Overexploitation"], "correctIndex": 2, "explanation": "Habitat loss and fragmentation is the primary driver of species decline and extinction worldwide. While all four factors contribute significantly to biodiversity loss, the conversion and degradation of natural habitats affects more species across more ecosystems than any single other factor."},
    {"type": "quiz", "question": "An Indigenous Protected and Conserved Area (IPCA) differs from a standard national park primarily because:", "options": ["It protects only marine ecosystems", "Indigenous governments have the primary role in governance and management", "It does not allow any human presence or activity", "It is managed solely by federal wildlife biologists"], "correctIndex": 1, "explanation": "IPCAs are areas where Indigenous governments hold primary authority over land and resource management, integrating Indigenous law, governance systems, and traditional ecological knowledge with Western conservation science. This governance model is distinct from conventional protected areas where management authority rests with federal or provincial governments."}
  ]'::jsonb,
  '[
    {"term": "Habitat Fragmentation", "definition": "The division of continuous habitat into smaller, isolated patches by human activities, increasing edge effects and reducing effective population size."},
    {"term": "Invasive Species", "definition": "An organism introduced outside its native range that spreads rapidly and negatively impacts native species, communities, or ecosystems."},
    {"term": "Minimum Viable Population (MVP)", "definition": "The smallest population size estimated to have a specified probability of surviving for a defined period, accounting for demographic, genetic, and environmental variability."},
    {"term": "Population Viability Analysis (PVA)", "definition": "A modelling approach that integrates demographic and genetic data to assess the risk of extinction for a population over time."},
    {"term": "In Situ Conservation", "definition": "Conservation of species within their natural habitats, such as through protected areas or sustainable land management."},
    {"term": "Ex Situ Conservation", "definition": "Conservation of species outside their natural habitats, such as in seed banks, botanical gardens, or captive breeding programs."},
    {"term": "Indigenous Protected and Conserved Area (IPCA)", "definition": "A land or water area where Indigenous governments hold the primary role in protecting and conserving ecosystems using Indigenous law, governance, and knowledge."},
    {"term": "Wildlife Corridor", "definition": "A strip of habitat linking isolated habitat patches, allowing animals to disperse, mate, and maintain genetic diversity."},
    {"term": "Species-Area Relationship", "definition": "The empirical pattern that larger habitat areas support more species, described by the equation S = cA^z."}
  ]'::jsonb,
  'Woodland Cree, Dene, and Nêhiyaw communities are leading conservation efforts on traditional territories — managing bison recovery, protecting old-growth boreal forest, and reviving cultural burning. Research consistently shows biodiversity outcomes on Indigenous-managed lands equal or exceed those on government-managed protected areas.',
  40, false)
RETURNING id INTO v_ch;

END $$;

-- ============================================================================
-- TEXTBOOK 2: WolfWhale Chemistry 30
-- Slug: wolfwhale-chemistry-30
-- ============================================================================

DO $$
DECLARE
  v_tenant UUID := '00000000-0000-0000-0000-000000000001';
  v_book UUID;
  v_ch UUID;
BEGIN

SELECT id INTO v_book FROM textbooks WHERE tenant_id = v_tenant AND slug = 'wolfwhale-chemistry-30';

-- ----------------------------------------------------------------------------
-- Chapter 1: Thermochemistry
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 1, 'Thermochemistry', 'thermochemistry',
  'Energy changes in chemical reactions — measuring heat with calorimetry, calculating enthalpy changes using Hess''s law and bond energies, and connecting reaction energetics to real Saskatchewan industries.',
  '[
    {"type": "heading", "level": 1, "text": "Thermochemistry"},
    {"type": "text", "content": "Every chemical reaction either releases energy to its surroundings or absorbs energy from them. The combustion of natural gas heats Saskatchewan homes through long winters; the decomposition of potassium chlorate releases oxygen for industrial processes; the dissolution of potash fertiliser in soil releases a detectable warmth. Thermochemistry is the study of these energy exchanges — quantifying them, predicting them, and harnessing them in technology and industry."},
    {"type": "heading", "level": 2, "text": "Heat, Temperature, and Specific Heat Capacity"},
    {"type": "text", "content": "Heat (q) is the transfer of thermal energy between a system and its surroundings due to a temperature difference. It is measured in joules (J) or kilojoules (kJ). Temperature is a measure of the average kinetic energy of particles and is measured in kelvins (K) or degrees Celsius (°C). Specific heat capacity (c) is the amount of heat required to raise the temperature of one gram of a substance by one degree Celsius. Water has an exceptionally high specific heat capacity of 4.18 J·g⁻¹·°C⁻¹, which moderates the climate of communities near large lakes such as Last Mountain Lake in central Saskatchewan. The fundamental relationship is: q = mcΔT, where m is mass, c is specific heat capacity, and ΔT is the change in temperature."},
    {"type": "heading", "level": 2, "text": "Calorimetry"},
    {"type": "text", "content": "Calorimetry is the experimental measurement of heat flow in chemical reactions. In a simple coffee-cup calorimeter (two nested polystyrene cups), the heat released by a reaction is absorbed by a known mass of water, and the temperature change is measured. Because the calorimeter is assumed to be perfectly insulating, q_reaction = −q_water = −mcΔT. Bomb calorimeters are closed, rigid steel vessels used to measure combustion reactions at constant volume; they provide more accurate results than coffee-cup calorimeters because heat losses to the surroundings are minimised. Calorimetric data from the combustion of Saskatchewan natural gas and crude oil are used to calculate energy content values reported to customers and regulators."},
    {"type": "callout", "style": "info", "title": "Exothermic vs Endothermic", "content": "In an exothermic reaction, the system releases heat to the surroundings — the temperature of the surroundings rises and ΔH is negative. Combustion, neutralisation, and many precipitation reactions are exothermic. In an endothermic reaction, the system absorbs heat from the surroundings — the temperature of the surroundings drops and ΔH is positive. Dissolving ammonium nitrate in water and photosynthesis are endothermic processes. Hand warmers exploit exothermic reactions; cold packs exploit endothermic dissolution."},
    {"type": "heading", "level": 2, "text": "Enthalpy and Hess''s Law"},
    {"type": "text", "content": "Enthalpy (H) is a thermodynamic quantity defined as the heat content of a system at constant pressure. The enthalpy change of a reaction (ΔH_rxn) represents the heat exchanged with the surroundings when a reaction occurs at constant pressure. Because enthalpy is a state function — its value depends only on the current state of the system, not on how it got there — we can add reactions and their enthalpy changes algebraically. Hess''s law states that the total enthalpy change for a reaction is independent of the pathway taken, providing we account properly for the direction and stoichiometry of each step. This allows chemists to calculate ΔH for reactions that cannot be measured directly by combining reactions whose enthalpies are known."},
    {"type": "callout", "style": "example", "title": "Worked Example: Hess''s Law", "content": "Question: Calculate ΔH for the reaction C(s) + ½O₂(g) → CO(g), given:\n  (1) C(s) + O₂(g) → CO₂(g)          ΔH₁ = −393.5 kJ\n  (2) CO(g) + ½O₂(g) → CO₂(g)        ΔH₂ = −283.0 kJ\n\nStrategy: Target reaction = Reaction (1) − Reaction (2).\nReverse reaction (2): CO₂(g) → CO(g) + ½O₂(g)   ΔH = +283.0 kJ\nAdd to reaction (1):  C(s) + O₂(g) → CO₂(g)      ΔH = −393.5 kJ\n\nNet: C(s) + O₂(g) + CO₂(g) → CO₂(g) + CO(g) + ½O₂(g)\nCancel CO₂ and ½O₂ from both sides:\nC(s) + ½O₂(g) → CO(g)   ΔH = −393.5 + 283.0 = −110.5 kJ\n\nAnswer: ΔH = −110.5 kJ. The formation of carbon monoxide from its elements is exothermic."},
    {"type": "heading", "level": 2, "text": "Bond Energies"},
    {"type": "text", "content": "Chemical reactions involve breaking bonds in reactants and forming bonds in products. Breaking bonds requires energy (endothermic); forming bonds releases energy (exothermic). The bond dissociation energy (BDE) is the average energy required to break one mole of a specific bond in the gas phase. We can estimate ΔH_rxn using bond energies: ΔH_rxn ≈ Σ(bonds broken) − Σ(bonds formed). This approach uses average bond energies and gives approximate results, but it is invaluable for understanding why certain reactions are energetically favourable and for predicting the energy content of fuels — a critical calculation for Saskatchewan''s natural gas and uranium industries."},
    {"type": "quiz", "question": "A student mixes 50.0 mL of 1.0 mol/L HCl with 50.0 mL of 1.0 mol/L NaOH in a coffee-cup calorimeter. The temperature rises from 22.0 °C to 29.4 °C. Assuming the density of the solution is 1.00 g/mL and c = 4.18 J·g⁻¹·°C⁻¹, what is q for the reaction? (Select the closest answer.)", "options": ["−3.09 kJ", "+3.09 kJ", "−6.18 kJ", "+6.18 kJ"], "correctIndex": 0, "explanation": "Total mass = 100.0 g; ΔT = 29.4 − 22.0 = 7.4 °C. q_water = mcΔT = 100.0 × 4.18 × 7.4 = 3 093 J ≈ 3.09 kJ. Since the water absorbed heat, q_reaction = −3.09 kJ. The reaction is exothermic (ΔH is negative)."},
    {"type": "quiz", "question": "Hess''s law is valid because enthalpy is:", "options": ["Dependent on the reaction pathway", "A state function independent of pathway", "Always negative for spontaneous reactions", "Equal to the internal energy of the system"], "correctIndex": 1, "explanation": "Hess''s law works because enthalpy is a state function — its value depends only on the initial and final states of the system, not on the path taken between them. This allows enthalpy changes for individual steps to be added algebraically to obtain the overall ΔH."}
  ]'::jsonb,
  '[
    {"term": "Thermochemistry", "definition": "The branch of chemistry concerned with the heat changes that accompany chemical reactions and phase transitions."},
    {"term": "Specific Heat Capacity (c)", "definition": "The quantity of heat required to raise the temperature of one gram of a substance by one degree Celsius; units are J·g⁻¹·°C⁻¹."},
    {"term": "Calorimetry", "definition": "The experimental measurement of heat flow in physical or chemical processes using an insulated device called a calorimeter."},
    {"term": "Enthalpy (H)", "definition": "A thermodynamic state function representing heat content at constant pressure; ΔH equals the heat exchanged with the surroundings during a constant-pressure process."},
    {"term": "Exothermic Reaction", "definition": "A reaction that releases heat to the surroundings, resulting in a negative ΔH and a rise in the temperature of the surroundings."},
    {"term": "Endothermic Reaction", "definition": "A reaction that absorbs heat from the surroundings, resulting in a positive ΔH and a decrease in the temperature of the surroundings."},
    {"term": "Hess''s Law", "definition": "The principle that the total enthalpy change for a reaction equals the sum of enthalpy changes for any sequence of steps that leads from reactants to products."},
    {"term": "Bond Dissociation Energy (BDE)", "definition": "The average energy required to break one mole of a specific covalent bond in gaseous molecules, used to estimate ΔH from structural data."},
    {"term": "Standard Enthalpy of Formation (ΔH°f)", "definition": "The enthalpy change when one mole of a compound is formed from its elements in their standard states at 25 °C and 101.3 kPa."}
  ]'::jsonb,
  NULL,
  35, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 2: Entropy & Gibbs Free Energy
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 2, 'Entropy & Gibbs Free Energy', 'entropy-and-gibbs-free-energy',
  'The second law of thermodynamics, entropy as a measure of disorder, and how Gibbs free energy combines enthalpy and entropy to predict whether a reaction will proceed spontaneously.',
  '[
    {"type": "heading", "level": 1, "text": "Entropy & Gibbs Free Energy"},
    {"type": "text", "content": "Why does a drop of dye spontaneously spread through a beaker of water but never spontaneously collect itself back into a drop? Why does ice melt at room temperature but water does not spontaneously freeze on a warm day? The answer lies in the second law of thermodynamics and the concept of entropy — a measure of the dispersal of energy and matter. Combining entropy with enthalpy, Josiah Willard Gibbs developed a single quantity that predicts the spontaneity of any process under a given set of conditions."},
    {"type": "heading", "level": 2, "text": "Entropy and the Second Law"},
    {"type": "text", "content": "Entropy (S) is a thermodynamic state function that quantifies the number of possible microscopic arrangements (microstates) available to a system. The more microstates, the higher the entropy. Gases have more entropy than liquids, which have more than solids. Dissolving a solid in a solvent generally increases entropy. Reactions that produce more moles of gas than they consume typically increase entropy. The second law of thermodynamics states that for any spontaneous process, the total entropy of the universe (system + surroundings) must increase: ΔS_universe = ΔS_system + ΔS_surroundings > 0. An individual process can decrease the entropy of a system (e.g., freezing water decreases liquid entropy), provided the surroundings gain even more entropy (the heat released warms the surroundings)."},
    {"type": "callout", "style": "info", "title": "The Third Law of Thermodynamics", "content": "The third law states that the entropy of a perfect crystalline substance is exactly zero at absolute zero (0 K). This provides an absolute reference point for entropy, unlike enthalpy, for which only changes (not absolute values) can be measured. Standard molar entropies (S°) are tabulated at 25 °C and 101.3 kPa and can be used to calculate ΔS°_rxn = ΣS°(products) − ΣS°(reactants)."},
    {"type": "heading", "level": 2, "text": "Gibbs Free Energy"},
    {"type": "text", "content": "Gibbs free energy (G) elegantly combines enthalpy and entropy into a single criterion for spontaneity at constant temperature and pressure: ΔG = ΔH − TΔS. If ΔG < 0, the process is spontaneous (exergonic) in the forward direction. If ΔG > 0, the process is non-spontaneous in the forward direction (but spontaneous in reverse). If ΔG = 0, the system is at equilibrium. Note that spontaneous does not mean fast — the thermite reaction (iron oxide + aluminium) is highly spontaneous but requires ignition; diamond spontaneously converts to graphite but at a rate too slow to observe in a human lifetime."},
    {"type": "heading", "level": 2, "text": "Temperature Dependence of Spontaneity"},
    {"type": "text", "content": "The equation ΔG = ΔH − TΔS reveals that temperature governs which term dominates. When ΔH is negative (exothermic) and ΔS is positive, ΔG is always negative — the reaction is spontaneous at all temperatures. When ΔH is positive (endothermic) and ΔS is negative, ΔG is always positive — the reaction is never spontaneous. When the signs of ΔH and ΔS are the same, temperature determines the outcome: an endothermic reaction with a positive ΔS becomes spontaneous above a crossover temperature T_cross = ΔH / ΔS. For example, the thermal decomposition of calcium carbonate (limestone) is endothermic with a positive ΔS; it becomes spontaneous above approximately 840 °C — relevant to cement production and industrial calcination processes."},
    {"type": "callout", "style": "example", "title": "Worked Example: Gibbs Free Energy Calculation", "content": "Question: For the reaction N₂(g) + 3H₂(g) → 2NH₃(g) at 25 °C, ΔH° = −92.4 kJ and ΔS° = −198 J/K. Calculate ΔG° and determine whether the reaction is spontaneous at 25 °C.\n\nStep 1: Convert ΔS° to kJ/K: −198 J/K ÷ 1000 = −0.198 kJ/K\nStep 2: T = 25 + 273 = 298 K\nStep 3: ΔG° = ΔH° − TΔS° = −92.4 − (298)(−0.198) = −92.4 + 59.0 = −33.4 kJ\n\nAnswer: ΔG° = −33.4 kJ < 0, so the reaction is spontaneous at 25 °C. At higher temperatures, the −TΔS term becomes more positive and will eventually make ΔG positive, making the reaction non-spontaneous. This is why the Haber-Bosch process for ammonia synthesis uses moderate temperatures and high pressure."},
    {"type": "quiz", "question": "Which combination of ΔH and ΔS always produces a spontaneous reaction regardless of temperature?", "options": ["ΔH positive, ΔS positive", "ΔH negative, ΔS negative", "ΔH negative, ΔS positive", "ΔH positive, ΔS negative"], "correctIndex": 2, "explanation": "When ΔH < 0 and ΔS > 0, ΔG = ΔH − TΔS is always negative (a negative minus a positive times a positive temperature is always negative). This represents the ideal spontaneous reaction — exothermic and increasing disorder — favouring products at all temperatures."},
    {"type": "quiz", "question": "The dissolving of ammonium nitrate in water is endothermic yet occurs spontaneously at room temperature. What drives this spontaneity?", "options": ["The enthalpy change is negative", "The large positive entropy change from dissolving the ionic solid", "The reaction releases gases that increase pressure", "Water catalyses the decomposition"], "correctIndex": 1, "explanation": "When ΔH is positive (endothermic), spontaneity must be driven by entropy. Dissolving a solid ionic compound into separate hydrated ions dramatically increases the number of particles and their freedom of movement, producing a large positive ΔS. At room temperature, TΔS > ΔH, making ΔG negative and the process spontaneous."}
  ]'::jsonb,
  '[
    {"term": "Entropy (S)", "definition": "A thermodynamic state function measuring the degree of energy and matter dispersal in a system; quantitatively related to the number of possible microscopic arrangements (microstates)."},
    {"term": "Second Law of Thermodynamics", "definition": "The principle that the total entropy of the universe increases for any spontaneous process: ΔS_universe > 0."},
    {"term": "Third Law of Thermodynamics", "definition": "The principle that the entropy of a perfect crystalline substance approaches zero as temperature approaches absolute zero (0 K)."},
    {"term": "Gibbs Free Energy (G)", "definition": "A thermodynamic state function defined as G = H − TS; a negative ΔG indicates a spontaneous process at constant temperature and pressure."},
    {"term": "Spontaneous Process", "definition": "A process that proceeds in the forward direction without continuous external input of energy under the given conditions (ΔG < 0)."},
    {"term": "Exergonic", "definition": "Describes a process that releases free energy (ΔG < 0) and proceeds spontaneously."},
    {"term": "Endergonic", "definition": "Describes a process that requires input of free energy (ΔG > 0) and is non-spontaneous in the forward direction."},
    {"term": "Microstate", "definition": "A specific microscopic arrangement of the particles and energy in a system; entropy increases with the number of accessible microstates."}
  ]'::jsonb,
  NULL,
  35, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 3: Electrochemistry — Fundamentals
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 3, 'Electrochemistry: Fundamentals', 'electrochemistry-fundamentals',
  'Oxidation and reduction reactions, balancing redox equations using half-reactions, and the design and operation of voltaic (galvanic) electrochemical cells.',
  '[
    {"type": "heading", "level": 1, "text": "Electrochemistry: Fundamentals"},
    {"type": "text", "content": "Electrochemistry explores the interconversion of chemical energy and electrical energy through oxidation-reduction (redox) reactions. From the lithium-ion batteries powering smartphones and electric vehicles to the electrolysis tanks in Saskatchewan''s potash refining operations, redox chemistry underpins some of the most economically significant technologies of the modern world. Understanding electron transfer — who donates electrons and who accepts them — is the key to mastering this discipline."},
    {"type": "heading", "level": 2, "text": "Oxidation States and Redox"},
    {"type": "text", "content": "An oxidation state (or oxidation number) is a bookkeeping tool that tracks the apparent charge on an atom within a compound, assuming complete transfer of bonding electrons to the more electronegative partner. Rules for assigning oxidation states: elements in their pure form have oxidation state 0; monatomic ions have an oxidation state equal to their charge; oxygen is typically −2 (except in peroxides, −1); hydrogen is typically +1 (except in metal hydrides, −1); the sum of oxidation states in a neutral compound equals zero. Oxidation is defined as an increase in oxidation state (loss of electrons); reduction is a decrease in oxidation state (gain of electrons). The mnemonic OIL RIG (Oxidation Is Loss, Reduction Is Gain) is widely used. In any redox reaction, the substance that is oxidised (loses electrons) is the reducing agent; the substance that is reduced (gains electrons) is the oxidising agent."},
    {"type": "callout", "style": "info", "title": "Balancing Redox Equations: Half-Reaction Method", "content": "Complex redox equations are balanced by splitting the reaction into two half-reactions — one for oxidation and one for reduction — then balancing each separately before combining them. In acidic solution: (1) balance all atoms except H and O; (2) balance O by adding H₂O; (3) balance H by adding H⁺; (4) balance charge by adding electrons; (5) multiply half-reactions so electrons cancel; (6) add and simplify. In basic solution, add OH⁻ to neutralise H⁺ after balancing in acid."},
    {"type": "heading", "level": 2, "text": "Voltaic (Galvanic) Cells"},
    {"type": "text", "content": "A voltaic cell (also called a galvanic cell) converts spontaneous chemical energy from a redox reaction into electrical energy. It consists of two half-cells, each containing an electrode immersed in an electrolyte solution. In the classic Daniell cell, zinc metal is oxidised at the anode (Zn → Zn²⁺ + 2e⁻) and copper ions are reduced at the cathode (Cu²⁺ + 2e⁻ → Cu). Electrons flow through an external circuit from the anode to the cathode, constituting an electrical current. A salt bridge — a tube containing an inert electrolyte solution — completes the internal circuit by allowing ion flow that maintains electrical neutrality in each half-cell. The cell potential (E_cell) is measured in volts and represents the driving force for electron flow."},
    {"type": "heading", "level": 2, "text": "Standard Reduction Potentials"},
    {"type": "text", "content": "Standard reduction potentials (E°_red) are tabulated values that measure the tendency of a half-reaction to proceed as a reduction under standard conditions (1 mol/L, 25 °C, 101.3 kPa), referenced against the standard hydrogen electrode (SHE, E° = 0.00 V). A more positive E°_red means a stronger tendency to gain electrons — the species is a better oxidising agent. To calculate the standard cell potential: E°_cell = E°_cathode − E°_anode. A positive E°_cell indicates a spontaneous reaction. The relationship between E°_cell and Gibbs free energy is: ΔG° = −nFE°_cell, where n is the number of moles of electrons transferred and F is Faraday''s constant (96 485 C/mol)."},
    {"type": "callout", "style": "example", "title": "Worked Example: Standard Cell Potential", "content": "Question: Calculate E°_cell for a voltaic cell constructed from Cu²⁺/Cu and Zn²⁺/Zn half-cells. E°(Cu²⁺/Cu) = +0.34 V; E°(Zn²⁺/Zn) = −0.76 V.\n\nStep 1: The more positive reduction potential is at the cathode: Cu²⁺ + 2e⁻ → Cu  (cathode, reduction).\nStep 2: The more negative potential is at the anode: Zn → Zn²⁺ + 2e⁻  (anode, oxidation).\nStep 3: E°_cell = E°_cathode − E°_anode = 0.34 − (−0.76) = +1.10 V.\n\nAnswer: E°_cell = +1.10 V. A positive value confirms the reaction is spontaneous under standard conditions. ΔG° = −nFE° = −(2)(96 485)(1.10) = −212 267 J ≈ −212 kJ."},
    {"type": "quiz", "question": "In a voltaic cell, which electrode undergoes oxidation?", "options": ["Cathode", "Salt bridge", "Anode", "Reference electrode"], "correctIndex": 2, "explanation": "At the anode of a voltaic cell, the electrode material or a species in solution loses electrons (oxidation). Electrons then flow through the external circuit from the anode to the cathode, where reduction occurs. Memory aid: AnOx (Anode Oxidation), RedCat (Reduction Cathode)."},
    {"type": "quiz", "question": "In the half-reaction MnO₄⁻ + 8H⁺ + 5e⁻ → Mn²⁺ + 4H₂O, permanganate ion (MnO₄⁻) is acting as:", "options": ["A reducing agent", "An oxidising agent", "A spectator ion", "A Brønsted-Lowry acid"], "correctIndex": 1, "explanation": "MnO₄⁻ gains electrons (manganese goes from +7 to +2) — it is reduced. Any species that gains electrons (and is itself reduced) is acting as an oxidising agent. Permanganate is one of the strongest common oxidising agents in aqueous solution."}
  ]'::jsonb,
  '[
    {"term": "Oxidation", "definition": "The loss of electrons by a species in a redox reaction, accompanied by an increase in oxidation state."},
    {"term": "Reduction", "definition": "The gain of electrons by a species in a redox reaction, accompanied by a decrease in oxidation state."},
    {"term": "Oxidation State", "definition": "A number assigned to an atom in a compound that represents the charge it would have if bonding electrons were completely transferred to the more electronegative atom."},
    {"term": "Reducing Agent", "definition": "The species that donates electrons (is oxidised) in a redox reaction."},
    {"term": "Oxidising Agent", "definition": "The species that accepts electrons (is reduced) in a redox reaction."},
    {"term": "Voltaic (Galvanic) Cell", "definition": "An electrochemical cell in which a spontaneous redox reaction generates electrical energy; it has an anode where oxidation occurs and a cathode where reduction occurs."},
    {"term": "Salt Bridge", "definition": "A tube containing an inert electrolyte that connects the two half-cells of a voltaic cell, allowing ion flow to maintain electrical neutrality."},
    {"term": "Standard Reduction Potential (E°_red)", "definition": "The potential of a half-reaction measured under standard conditions relative to the standard hydrogen electrode; indicates the tendency to undergo reduction."},
    {"term": "Faraday''s Constant (F)", "definition": "The electric charge carried by one mole of electrons, approximately 96 485 coulombs per mole."}
  ]'::jsonb,
  NULL,
  38, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 4: Electrochemistry — Applications
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 4, 'Electrochemistry: Applications', 'electrochemistry-applications',
  'Real-world electrochemistry — batteries, fuel cells, electrolysis, and corrosion — with a focus on Saskatchewan''s potash and uranium mining industries and emerging green energy technologies.',
  '[
    {"type": "heading", "level": 1, "text": "Electrochemistry: Applications"},
    {"type": "text", "content": "The principles of electrochemistry explored in Chapter 3 translate directly into technologies that shape Saskatchewan''s economy and Canada''s energy future. The province hosts some of the world''s largest potash mines — ore bodies that require electrochemical processing — and is a global supplier of uranium fuel for nuclear reactors that generate electricity through processes intimately linked to thermochemistry and electrochemistry. Meanwhile, the global push toward electric vehicles and renewable energy is driving explosive demand for advanced batteries and hydrogen fuel cells, many of which rely on Saskatchewan resources."},
    {"type": "heading", "level": 2, "text": "Primary and Secondary Batteries"},
    {"type": "text", "content": "A primary battery cannot be recharged — its redox reaction is irreversible, and once the reactants are consumed the battery is discarded. The alkaline battery (the standard AA cell) is a familiar primary battery that uses zinc as the anode and manganese dioxide as the cathode in an alkaline (KOH) electrolyte, generating approximately 1.5 V. A secondary (rechargeable) battery can be regenerated by applying an external electrical current that reverses the redox reaction. Lithium-ion batteries — now dominant in portable electronics and electric vehicles — use a graphite anode and a lithium metal oxide cathode separated by a lithium-ion conducting electrolyte. During discharge, lithium ions migrate from the anode to the cathode through the electrolyte while electrons flow through the external circuit. During charging, the process reverses. Lithium-ion cells can achieve over 4 V and have high energy density, but they require lithium, cobalt, and other critical minerals whose ethical and environmental sourcing is an active global concern."},
    {"type": "callout", "style": "info", "title": "Potash Mining and Electrolysis in Saskatchewan", "content": "Saskatchewan holds roughly 50% of the world''s known potash reserves. After ore is extracted from underground mines near Esterhazy, Rocanville, and Allan, it undergoes flotation and evaporative crystallisation to yield potassium chloride (KCl). Some downstream processes electrolyse concentrated KCl solutions (brine) in a chlor-alkali process: 2KCl(aq) + 2H₂O(l) → Cl₂(g) + 2KOH(aq) + H₂(g). The chlorine is used in water treatment and plastics manufacture; the potassium hydroxide finds applications in fertiliser formulations and industrial cleaning products."},
    {"type": "heading", "level": 2, "text": "Fuel Cells"},
    {"type": "text", "content": "A hydrogen fuel cell converts chemical energy directly into electrical energy with water as the only direct emission. In a proton-exchange membrane (PEM) fuel cell, hydrogen gas is fed to the anode where it is oxidised (H₂ → 2H⁺ + 2e⁻). Electrons flow through the external circuit, generating electricity, while protons cross a polymer membrane to the cathode, where they combine with oxygen and electrons to form water (O₂ + 4H⁺ + 4e⁻ → 2H₂O). Fuel cells are more energy-efficient than internal combustion engines because they convert chemical energy directly to electricity without an intermediate heat step. Saskatchewan is exploring the use of surplus wind energy from its prairie turbine farms to produce green hydrogen by electrolysis — hydrogen that could power fuel cells in trucks, trains, and industrial equipment."},
    {"type": "heading", "level": 2, "text": "Electrolysis"},
    {"type": "text", "content": "Electrolysis uses electrical energy to drive a non-spontaneous redox reaction. In an electrolytic cell, an external power supply forces electrons to flow in the opposite direction to what is thermodynamically favourable: the electrode connected to the negative terminal of the supply is the cathode (reduction occurs) and the electrode connected to the positive terminal is the anode (oxidation occurs). The amount of substance deposited or released during electrolysis is governed by Faraday''s laws: the mass deposited is proportional to the charge passed and inversely proportional to the number of electrons required per ion. Electrolysis is used to produce aluminium, chlorine, hydrogen, and to electroplate metals for corrosion protection — processes operating at large scale in Saskatchewan-linked supply chains."},
    {"type": "callout", "style": "example", "title": "Worked Example: Faraday''s Law of Electrolysis", "content": "Question: How long must a current of 2.50 A flow through a CuSO₄ solution to deposit exactly 1.27 g of copper at the cathode? (M_Cu = 63.5 g/mol; n = 2 electrons per Cu²⁺ ion.)\n\nStep 1: Moles of Cu deposited = 1.27 g ÷ 63.5 g/mol = 0.0200 mol\nStep 2: Moles of electrons required = 0.0200 mol Cu × 2 mol e⁻/mol Cu = 0.0400 mol e⁻\nStep 3: Charge required = 0.0400 mol × 96 485 C/mol = 3 859 C\nStep 4: Time = Charge / Current = 3 859 C ÷ 2.50 A = 1 544 s ≈ 25.7 minutes\n\nAnswer: A current of 2.50 A must flow for approximately 25.7 minutes to deposit 1.27 g of copper."},
    {"type": "heading", "level": 2, "text": "Corrosion and Cathodic Protection"},
    {"type": "text", "content": "Corrosion is the electrochemical deterioration of metals, most commonly the rusting of iron. In the presence of water and oxygen, iron acts as the anode in a spontaneous electrochemical cell: Fe(s) → Fe²⁺(aq) + 2e⁻ (oxidation). Electrons flow to a cathodic region on the same metal surface where oxygen is reduced. The resulting Fe²⁺ is further oxidised and hydrated to form rust (Fe₂O₃·xH₂O). Cathodic protection prevents corrosion by connecting the metal structure to a more easily oxidised sacrificial anode (typically magnesium or zinc), which corrodes preferentially while the iron remains the cathode and is protected. Saskatchewan''s extensive network of pipelines transporting natural gas and oil relies heavily on cathodic protection systems to prevent corrosion-induced failures."},
    {"type": "quiz", "question": "During the electrolysis of molten sodium chloride, what forms at the cathode?", "options": ["Chlorine gas", "Sodium metal", "Sodium hydroxide", "Hydrogen gas"], "correctIndex": 1, "explanation": "In the electrolytic cell, the cathode is connected to the negative terminal and undergoes reduction. In molten NaCl, the available cation is Na⁺. Reduction at the cathode: Na⁺ + e⁻ → Na(l). Chlorine gas forms at the anode: 2Cl⁻ → Cl₂(g) + 2e⁻."},
    {"type": "quiz", "question": "In cathodic protection, the sacrificial anode attached to an iron pipeline must:", "options": ["Be a stronger oxidising agent than iron", "Be a less active metal than iron", "Be a more active metal than iron", "Be an electrical insulator"], "correctIndex": 2, "explanation": "The sacrificial anode must oxidise more readily than the iron it protects — it must be a more active (higher on the activity series / more negative reduction potential) metal. Magnesium and zinc are commonly used because they are oxidised preferentially, protecting the iron pipeline from corrosion."}
  ]'::jsonb,
  '[
    {"term": "Primary Battery", "definition": "A non-rechargeable electrochemical cell in which the redox reaction is irreversible; discarded once reactants are consumed."},
    {"term": "Secondary Battery", "definition": "A rechargeable electrochemical cell in which the redox reaction can be reversed by applying an external electric current."},
    {"term": "Lithium-Ion Battery", "definition": "A rechargeable battery that stores energy through the reversible intercalation of lithium ions between graphite and metal oxide electrodes."},
    {"term": "Fuel Cell", "definition": "An electrochemical device that continuously converts the chemical energy of a fuel (typically hydrogen) and an oxidant (typically oxygen) into electrical energy."},
    {"term": "Electrolytic Cell", "definition": "An electrochemical cell in which an external electrical source drives a non-spontaneous redox reaction."},
    {"term": "Faraday''s Law of Electrolysis", "definition": "The principle that the amount of substance deposited at an electrode is proportional to the total charge passed and inversely proportional to the number of electrons required per ion."},
    {"term": "Corrosion", "definition": "The electrochemical deterioration of a metal, typically by oxidation in the presence of moisture and oxygen."},
    {"term": "Cathodic Protection", "definition": "A corrosion prevention technique in which a more active sacrificial anode is connected to the metal structure, causing the sacrificial anode to oxidise preferentially."},
    {"term": "Chlor-Alkali Process", "definition": "The industrial electrolysis of concentrated sodium or potassium chloride brine to produce chlorine gas and metal hydroxide."}
  ]'::jsonb,
  NULL,
  40, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 5: Chemical Kinetics
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 5, 'Chemical Kinetics', 'chemical-kinetics',
  'The factors that control the speed of chemical reactions — concentration, temperature, surface area, and catalysts — expressed quantitatively through rate laws and activation energy theory.',
  '[
    {"type": "heading", "level": 1, "text": "Chemical Kinetics"},
    {"type": "text", "content": "Thermodynamics tells us whether a reaction can occur; kinetics tells us how fast it will. The combustion of methane in a natural gas furnace and the slow weathering of limestone cliffs in the Qu''Appelle Valley are both thermodynamically spontaneous, yet they occur at vastly different rates. Chemical kinetics — the study of reaction rates and the factors that influence them — is essential for designing industrial processes, developing pharmaceuticals, understanding atmospheric chemistry, and predicting how contaminants move through Saskatchewan''s groundwater."},
    {"type": "heading", "level": 2, "text": "Measuring Reaction Rate"},
    {"type": "text", "content": "The rate of a chemical reaction is the change in concentration of a reactant or product per unit time. For a reaction aA + bB → cC + dD, the rate can be expressed in terms of any participant: Rate = −(1/a)(Δ[A]/Δt) = −(1/b)(Δ[B]/Δt) = (1/c)(Δ[C]/Δt) = (1/d)(Δ[D]/Δt). The negative sign for reactants indicates that their concentrations decrease over time. Rates are typically measured in mol·L⁻¹·s⁻¹ (for solution reactions) or mol·L⁻¹·min⁻¹. Several experimental methods are used to monitor concentration changes: spectrophotometry (measuring light absorbance), gas collection (monitoring volume or pressure changes), and conductivity measurements."},
    {"type": "heading", "level": 2, "text": "Rate Laws and Reaction Order"},
    {"type": "text", "content": "The rate law expresses how the rate depends on the concentration of reactants: Rate = k[A]^m[B]^n, where k is the rate constant, and m and n are the reaction orders with respect to each reactant. These orders must be determined experimentally — they cannot be deduced from the stoichiometric coefficients of the balanced equation. If m = 1, the reaction is first-order with respect to A (doubling [A] doubles the rate). If m = 2, it is second-order (doubling [A] quadruples the rate). The overall reaction order is the sum m + n. The rate constant k has units that depend on the overall order and is temperature-dependent. For a first-order reaction, the half-life (t₁/₂ = 0.693/k) is constant regardless of concentration — a property used in radioactive decay calculations and in pharmacokinetics."},
    {"type": "callout", "style": "info", "title": "Collision Theory", "content": "For a reaction to occur, reactant particles must collide with sufficient energy and with the correct geometric orientation. Collision theory states that the rate is proportional to the collision frequency multiplied by the fraction of collisions that have energy ≥ Ea (activation energy) and the fraction with correct orientation. Increasing temperature raises the average kinetic energy of particles, dramatically increasing the fraction of successful collisions. As a rough rule, a 10 °C rise in temperature roughly doubles the reaction rate for many common reactions."},
    {"type": "heading", "level": 2, "text": "Activation Energy and the Arrhenius Equation"},
    {"type": "text", "content": "Activation energy (Ea) is the minimum energy that colliding particles must possess for a reaction to occur. Even for exothermic reactions, an energy barrier must be overcome. The activated complex (transition state) is the unstable, high-energy arrangement of atoms at the top of the energy barrier. The Arrhenius equation relates the rate constant to activation energy and temperature: k = Ae^(−Ea/RT), where A is the frequency factor (related to collision frequency and orientation), R is the gas constant (8.314 J·mol⁻¹·K⁻¹), and T is the absolute temperature. Taking the natural log: ln k = ln A − Ea/RT. A plot of ln k vs. 1/T yields a straight line with slope −Ea/R, allowing Ea to be determined experimentally."},
    {"type": "callout", "style": "example", "title": "Worked Example: Determining Reaction Order", "content": "Question: Use the following initial rate data for the reaction A + B → C to determine the rate law.\n\nExperiment | [A] (mol/L) | [B] (mol/L) | Initial Rate (mol/L·s)\n1          | 0.10        | 0.10        | 2.0 × 10⁻³\n2          | 0.20        | 0.10        | 4.0 × 10⁻³\n3          | 0.10        | 0.30        | 1.8 × 10⁻²\n\nStep 1: Compare Expts 1 and 2 ([B] constant, [A] doubles): rate doubles → 1st order in A.\nStep 2: Compare Expts 1 and 3 ([A] constant, [B] triples): rate increases by 1.8×10⁻²/2.0×10⁻³ = 9 = 3². → 2nd order in B.\nStep 3: Rate = k[A]¹[B]². Overall order = 3.\nStep 4: Find k using Expt 1: 2.0×10⁻³ = k(0.10)(0.10)² → k = 2.0 mol⁻²·L²·s⁻¹.\n\nAnswer: Rate = 2.0[A][B]²."},
    {"type": "heading", "level": 2, "text": "Catalysts"},
    {"type": "text", "content": "A catalyst increases the rate of a reaction without being consumed in the process. It does so by providing an alternative reaction pathway with a lower activation energy, increasing the fraction of collisions that result in reaction. Homogeneous catalysts exist in the same phase as the reactants (e.g., sulfuric acid catalysing ester formation in solution). Heterogeneous catalysts are in a different phase (e.g., platinum or palladium metals catalysing the hydrogenation of vegetable oils, or vanadium pentoxide catalysing SO₂ oxidation in the contact process for sulfuric acid manufacture). Enzymes are biological catalysts — typically proteins — that are exquisitely specific and operate under mild conditions. Catalytic converters in vehicle exhaust systems use platinum, palladium, and rhodium to convert harmful CO and NOₓ emissions into CO₂, N₂, and H₂O — a heterogeneous catalysis application affecting every driver in Saskatchewan."},
    {"type": "quiz", "question": "In an experiment, tripling the concentration of reactant X triples the reaction rate, while doubling the concentration of reactant Y quadruples the rate. What is the overall order of the reaction?", "options": ["First order", "Second order", "Third order", "Fourth order"], "correctIndex": 2, "explanation": "Tripling [X] triples the rate → first-order in X (m = 1). Doubling [Y] quadruples the rate → 2² = 4 → second-order in Y (n = 2). Overall order = m + n = 1 + 2 = 3 (third order)."},
    {"type": "quiz", "question": "How does a catalyst increase reaction rate?", "options": ["By increasing the activation energy", "By providing an alternative pathway with lower activation energy", "By raising the temperature of the reaction", "By increasing the concentrations of reactants"], "correctIndex": 1, "explanation": "A catalyst provides an alternative reaction mechanism (pathway) with a lower activation energy than the uncatalysed route. This increases the fraction of collisions that possess enough energy to overcome the barrier, raising the reaction rate without being consumed or changing the overall thermodynamics of the reaction."}
  ]'::jsonb,
  '[
    {"term": "Reaction Rate", "definition": "The change in concentration of a reactant or product per unit time, typically expressed in mol·L⁻¹·s⁻¹."},
    {"term": "Rate Law", "definition": "An equation expressing the reaction rate as a function of reactant concentrations and a rate constant: Rate = k[A]^m[B]^n."},
    {"term": "Rate Constant (k)", "definition": "The proportionality constant in the rate law; its value depends on the reaction and temperature but not on reactant concentrations."},
    {"term": "Reaction Order", "definition": "The exponent of a reactant''s concentration in the rate law, determined experimentally; the overall order is the sum of all exponents."},
    {"term": "Activation Energy (Ea)", "definition": "The minimum energy required for a collision between reactant molecules to result in a chemical reaction."},
    {"term": "Transition State", "definition": "The unstable, high-energy arrangement of atoms at the peak of the energy barrier between reactants and products; also called the activated complex."},
    {"term": "Arrhenius Equation", "definition": "k = Ae^(−Ea/RT); relates the rate constant to activation energy and temperature, predicting how rate changes with temperature."},
    {"term": "Catalyst", "definition": "A substance that increases reaction rate by providing an alternative pathway with lower activation energy, without being consumed in the overall reaction."},
    {"term": "Half-Life (t₁/₂)", "definition": "The time required for the concentration of a reactant to decrease to half its initial value; for a first-order reaction, t₁/₂ = 0.693/k."}
  ]'::jsonb,
  NULL,
  38, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 6: Chemical Equilibrium
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 6, 'Chemical Equilibrium', 'chemical-equilibrium',
  'Dynamic equilibrium in reversible reactions, the equilibrium constant expression, Le Chatelier''s principle, and ICE table calculations applied to industrial processes.',
  '[
    {"type": "heading", "level": 1, "text": "Chemical Equilibrium"},
    {"type": "text", "content": "Many chemical reactions do not proceed to completion. Instead, they reach a state where the forward and reverse reactions occur at equal rates, so the concentrations of reactants and products remain constant. This state is called chemical equilibrium. Understanding equilibrium is essential for optimising industrial syntheses — from ammonia production for fertilisers that sustain Saskatchewan''s crop yields to the refining of sulfur recovered from fossil fuels at Saskatchewan''s heavy oil operations."},
    {"type": "heading", "level": 2, "text": "The Equilibrium Constant (K)"},
    {"type": "text", "content": "For a general reversible reaction aA + bB ⇌ cC + dD at constant temperature, the equilibrium constant expression is: K = [C]^c[D]^d / ([A]^a[B]^b). This expression, derived from the law of mass action, includes only species in the aqueous or gas phase — pure solids and pure liquids are omitted because their concentrations are constant. K_c uses molar concentrations; K_p uses partial pressures (for gas-phase reactions) and is related to K_c by K_p = K_c(RT)^Δn, where Δn is the change in moles of gas. A large K (≫ 1) indicates that products are strongly favoured at equilibrium; a small K (≪ 1) indicates reactants predominate. K is dimensionless and depends only on temperature."},
    {"type": "callout", "style": "info", "title": "Reaction Quotient (Q)", "content": "The reaction quotient Q has the same form as K but uses concentrations at any point in time, not just at equilibrium. Comparing Q to K predicts the direction the reaction will shift: if Q < K, the reaction proceeds forward (toward products); if Q > K, the reaction shifts reverse (toward reactants); if Q = K, the system is at equilibrium. Q is invaluable for predicting what will happen when a system is disturbed."},
    {"type": "heading", "level": 2, "text": "Le Chatelier''s Principle"},
    {"type": "text", "content": "Le Chatelier''s principle states that when a system at equilibrium is subjected to a stress, it will shift in the direction that partially relieves that stress. Stresses include changes in concentration, pressure (for gas-phase reactions), and temperature. Adding a reactant shifts equilibrium toward products; removing a product has the same effect. Increasing pressure favours the side with fewer moles of gas. Temperature changes affect K itself: for an exothermic reaction, raising temperature decreases K (shifts toward reactants); for an endothermic reaction, raising temperature increases K (shifts toward products). Catalysts do not shift equilibrium — they only help the system reach equilibrium faster. The Haber-Bosch process applies Le Chatelier''s principle to maximise ammonia yield: high pressure (150–300 atm) and moderate temperature (400–500 °C) are chosen as a compromise between yield and reaction rate."},
    {"type": "heading", "level": 2, "text": "ICE Tables"},
    {"type": "text", "content": "ICE tables (Initial, Change, Equilibrium) provide a systematic method for calculating equilibrium concentrations from initial conditions and the equilibrium constant. Set up the table with columns for each species and rows for initial concentrations, the change (expressed in terms of a variable x), and the equilibrium concentrations. Substitute the equilibrium expressions into the K expression and solve for x. When K is small, the change x may be negligible compared with initial concentrations — the simplifying assumption x ≪ [initial] can be applied and verified (x should be less than 5% of the initial concentration). When K is large, the reaction nearly goes to completion and a different simplification applies."},
    {"type": "callout", "style": "example", "title": "Worked Example: ICE Table Calculation", "content": "Question: For the reaction H₂(g) + I₂(g) ⇌ 2HI(g), K_c = 49.0 at 450 °C. If 1.00 mol each of H₂ and I₂ are placed in a 1.00 L flask, what are the equilibrium concentrations?\n\nICE Table (all concentrations in mol/L):\n         H₂      I₂      2HI\nI:      1.00    1.00     0\nC:       −x     −x     +2x\nE:    1.00−x  1.00−x   2x\n\nK_c = (2x)² / [(1.00−x)(1.00−x)] = 4x²/(1.00−x)² = 49.0\nTaking square roots: 2x/(1.00−x) = 7.0\n2x = 7.0 − 7.0x → 9.0x = 7.0 → x = 0.778 mol/L\n\n[H₂] = [I₂] = 1.00 − 0.778 = 0.222 mol/L; [HI] = 2(0.778) = 1.556 mol/L\n\nVerification: (1.556)² / (0.222)² = 2.42 / 0.0493 ≈ 49.1 ✓"},
    {"type": "quiz", "question": "For the equilibrium N₂(g) + 3H₂(g) ⇌ 2NH₃(g) + energy, what happens to K when temperature is increased?", "options": ["K increases", "K decreases", "K is unchanged", "K becomes zero"], "correctIndex": 1, "explanation": "This reaction is exothermic (releases energy). Treating heat as a product, increasing temperature adds stress to the product side, shifting equilibrium toward reactants. This means the equilibrium ratio of products to reactants decreases, so K decreases. For exothermic reactions, K decreases with increasing temperature."},
    {"type": "quiz", "question": "For the reaction 2SO₂(g) + O₂(g) ⇌ 2SO₃(g), K_c = [SO₃]² / ([SO₂]²[O₂]). In a mixture at equilibrium, more O₂ is added. The system will:", "options": ["Shift toward reactants, increasing [SO₂]", "Shift toward products, increasing [SO₃]", "Remain unchanged because K does not change", "Decrease K to compensate for the added O₂"], "correctIndex": 1, "explanation": "Adding O₂ increases its concentration, making Q < K. The system shifts forward (toward products) to restore equilibrium, consuming some of the added O₂ and some SO₂ while producing more SO₃. K itself does not change — it is temperature-dependent, not concentration-dependent."}
  ]'::jsonb,
  '[
    {"term": "Chemical Equilibrium", "definition": "The state of a reversible reaction in which the forward and reverse reaction rates are equal and the concentrations of all species remain constant over time."},
    {"term": "Equilibrium Constant (K)", "definition": "A dimensionless value equal to the ratio of product concentrations to reactant concentrations, each raised to the power of its stoichiometric coefficient, measured at equilibrium."},
    {"term": "Reaction Quotient (Q)", "definition": "An expression with the same form as K but calculated using concentrations at any point in time; comparing Q to K predicts the direction of equilibrium shift."},
    {"term": "Le Chatelier''s Principle", "definition": "The principle that a system at equilibrium will shift to partially counteract any imposed stress — changes in concentration, pressure, or temperature."},
    {"term": "ICE Table", "definition": "A tabular method for organising Initial concentrations, Changes during reaction, and Equilibrium concentrations to solve equilibrium problems."},
    {"term": "Law of Mass Action", "definition": "The principle that the equilibrium constant expression for a reaction is the product of product concentrations divided by the product of reactant concentrations, each raised to the power of its stoichiometric coefficient."},
    {"term": "K_p", "definition": "The equilibrium constant expressed in terms of partial pressures of gaseous species; related to K_c by K_p = K_c(RT)^Δn."},
    {"term": "Haber-Bosch Process", "definition": "The industrial synthesis of ammonia from nitrogen and hydrogen gases using an iron catalyst at high pressure and moderate temperature; the primary source of nitrogen fertiliser worldwide."}
  ]'::jsonb,
  NULL,
  40, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 7: Acids & Bases
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 7, 'Acids & Bases', 'acids-and-bases',
  'Brønsted-Lowry acid-base theory, the pH scale, weak acid-base equilibria, buffer systems, and titration curves — with applications to Saskatchewan soils, water treatment, and industrial chemistry.',
  '[
    {"type": "heading", "level": 1, "text": "Acids & Bases"},
    {"type": "text", "content": "Acid-base chemistry governs everything from the pH of Saskatchewan''s alkaline soils that require amendment before growing canola, to the acidic mine drainage produced near uranium and potash operations, to the buffering of blood that keeps your pH within the narrow range compatible with life. A rigorous understanding of acids and bases — their definitions, equilibria, and reactions — is indispensable for environmental chemistry, agriculture, medicine, and industrial processing."},
    {"type": "heading", "level": 2, "text": "Acid-Base Theories"},
    {"type": "text", "content": "The Arrhenius definition — acids produce H⁺ in water, bases produce OH⁻ — is intuitive but limited to aqueous solutions. The Brønsted-Lowry definition is more general: an acid is a proton donor and a base is a proton acceptor. This allows us to describe acid-base reactions in non-aqueous solvents and to recognise that every acid-base reaction involves a conjugate acid-base pair. When an acid HA donates a proton to water, it forms its conjugate base A⁻; water accepts the proton and becomes the conjugate acid H₃O⁺. The stronger the acid, the weaker its conjugate base, and vice versa. The Lewis definition is the broadest: a Lewis acid is an electron-pair acceptor and a Lewis base is an electron-pair donor — encompassing reactions that do not involve proton transfer at all."},
    {"type": "heading", "level": 2, "text": "The pH Scale and Water Autoionisation"},
    {"type": "text", "content": "Water undergoes autoionisation: H₂O(l) ⇌ H⁺(aq) + OH⁻(aq), with K_w = [H⁺][OH⁻] = 1.0 × 10⁻¹⁴ at 25 °C. The pH scale compresses the enormous range of hydrogen ion concentrations into a manageable logarithmic scale: pH = −log[H⁺]. At 25 °C, a neutral solution has pH = 7; acidic solutions have pH < 7; basic solutions have pH > 7. Similarly, pOH = −log[OH⁻], and pH + pOH = 14. Each unit change in pH represents a tenfold change in [H⁺]. The pH of Saskatchewan''s prairie soils typically ranges from 6.5 to 8.5; soils with pH above 7.5 may be calcareous or sodic, limiting nutrient availability for crops."},
    {"type": "callout", "style": "info", "title": "Weak Acids and Ka", "content": "Strong acids (HCl, H₂SO₄, HNO₃, HClO₄, HBr, HI) dissociate completely in water. Weak acids dissociate only partially, establishing an equilibrium described by the acid dissociation constant Ka: HA + H₂O ⇌ H₃O⁺ + A⁻; Ka = [H₃O⁺][A⁻]/[HA]. A larger Ka indicates a stronger weak acid. Similarly, weak bases have a base dissociation constant Kb. For a conjugate acid-base pair, Ka × Kb = K_w = 1.0 × 10⁻¹⁴."},
    {"type": "heading", "level": 2, "text": "Buffers"},
    {"type": "text", "content": "A buffer is a solution that resists changes in pH when small amounts of acid or base are added. It consists of a weak acid and its conjugate base (or a weak base and its conjugate acid) in comparable concentrations. When a small amount of strong acid is added, the conjugate base reacts with the added H⁺ ions, preventing a large pH drop. When a small amount of strong base is added, the weak acid donates protons to neutralise the added OH⁻. The Henderson-Hasselbalch equation gives the pH of a buffer: pH = pKa + log([A⁻]/[HA]). Buffers are most effective when pH ≈ pKa and when [A⁻]/[HA] is between 0.1 and 10. Blood is buffered primarily by the bicarbonate system (H₂CO₃/HCO₃⁻), maintaining pH between 7.35 and 7.45."},
    {"type": "callout", "style": "example", "title": "Worked Example: Buffer pH Using Henderson-Hasselbalch", "content": "Question: What is the pH of a buffer containing 0.200 mol/L acetic acid (CH₃COOH) and 0.350 mol/L sodium acetate (CH₃COONa)? Ka of acetic acid = 1.8 × 10⁻⁵.\n\nStep 1: pKa = −log(1.8 × 10⁻⁵) = 4.74\nStep 2: [A⁻] = [CH₃COO⁻] = 0.350 mol/L; [HA] = [CH₃COOH] = 0.200 mol/L\nStep 3: pH = pKa + log([A⁻]/[HA]) = 4.74 + log(0.350/0.200) = 4.74 + log(1.75) = 4.74 + 0.243 = 4.98\n\nAnswer: pH = 4.98. The buffer is slightly above the pKa because there is more conjugate base than weak acid."},
    {"type": "heading", "level": 2, "text": "Titration Curves"},
    {"type": "text", "content": "An acid-base titration involves the gradual addition of a standard solution of known concentration (the titrant) to an analyte solution of unknown concentration, monitoring pH as titrant is added. The equivalence point is where stoichiometric amounts of acid and base have reacted. For a strong acid-strong base titration, the equivalence point occurs at pH = 7. For a weak acid-strong base titration, the equivalence point is above 7 (because the conjugate base hydrolyses water to give OH⁻). An indicator — a weak acid with different colours in its acid and conjugate base forms — changes colour near the equivalence point. The half-equivalence point occurs when half the acid has been neutralised; at this point, [HA] = [A⁻] and pH = pKa, a useful method for determining Ka experimentally."},
    {"type": "quiz", "question": "A buffer is made from 0.10 mol/L HF (Ka = 7.2 × 10⁻⁴) and 0.10 mol/L NaF. What is the approximate pH?", "options": ["2.0", "3.14", "7.0", "10.86"], "correctIndex": 1, "explanation": "When [A⁻] = [HA], the Henderson-Hasselbalch equation gives pH = pKa + log(1) = pKa + 0 = pKa. pKa = −log(7.2 × 10⁻⁴) = 3.14. So pH ≈ 3.14."},
    {"type": "quiz", "question": "At the equivalence point of a weak acid-strong base titration, the solution pH is:", "options": ["Equal to 7 (neutral)", "Less than 7 (acidic)", "Greater than 7 (basic)", "Equal to the pKa of the weak acid"], "correctIndex": 2, "explanation": "At the equivalence point, all the weak acid has been converted to its conjugate base (A⁻). The conjugate base then undergoes hydrolysis: A⁻ + H₂O ⇌ HA + OH⁻, producing hydroxide ions and making the solution basic (pH > 7)."}
  ]'::jsonb,
  '[
    {"term": "Brønsted-Lowry Acid", "definition": "A species that donates a proton (H⁺) to another species in a chemical reaction."},
    {"term": "Brønsted-Lowry Base", "definition": "A species that accepts a proton (H⁺) from another species in a chemical reaction."},
    {"term": "Conjugate Acid-Base Pair", "definition": "Two species related by the loss or gain of a single proton; the acid has one more H than the conjugate base."},
    {"term": "pH", "definition": "A logarithmic scale for hydrogen ion concentration: pH = −log[H⁺]; values below 7 are acidic, above 7 are basic, equal to 7 are neutral at 25 °C."},
    {"term": "Ka (Acid Dissociation Constant)", "definition": "The equilibrium constant for the partial dissociation of a weak acid in water; a larger Ka indicates a stronger weak acid."},
    {"term": "Buffer", "definition": "A solution containing a weak acid and its conjugate base (or weak base and conjugate acid) that resists pH change upon addition of small amounts of acid or base."},
    {"term": "Henderson-Hasselbalch Equation", "definition": "pH = pKa + log([A⁻]/[HA]); gives the pH of a buffer solution from the pKa and the ratio of conjugate base to weak acid concentrations."},
    {"term": "Titration", "definition": "A laboratory technique in which a solution of known concentration (titrant) is added to a solution of unknown concentration to determine the analyte''s concentration."},
    {"term": "Equivalence Point", "definition": "The point in a titration where the moles of titrant added equal the stoichiometric amount needed to react completely with the analyte."}
  ]'::jsonb,
  NULL,
  40, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 8: Solubility Equilibrium
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 8, 'Solubility Equilibrium', 'solubility-equilibrium',
  'The solubility product constant Ksp, precipitation reactions, the common ion effect, and selective precipitation — with examples from water treatment and Saskatchewan mineral processing.',
  '[
    {"type": "heading", "level": 1, "text": "Solubility Equilibrium"},
    {"type": "text", "content": "When a sparingly soluble salt dissolves in water, it reaches equilibrium between the undissolved solid and its dissolved ions. This equilibrium governs the chemistry of natural water bodies, determines the purity of precipitated salts in industrial processes, and controls the release of metal ions in contaminated soils. Saskatchewan''s potash refining operations and uranium mine water treatment rely on precise control of solubility equilibria to separate, purify, and safely dispose of minerals."},
    {"type": "heading", "level": 2, "text": "The Solubility Product Constant (Ksp)"},
    {"type": "text", "content": "For a sparingly soluble salt MₐXᵦ dissolving in water, MₐXᵦ(s) ⇌ aM^n⁺(aq) + bX^m⁻(aq), the solubility product constant is: Ksp = [M^n⁺]^a[X^m⁻]^b. Pure solids are not included in the expression. A small Ksp indicates low solubility; a large Ksp indicates higher solubility. For example, AgCl has Ksp = 1.8 × 10⁻¹⁰ (very sparingly soluble), while CaCO₃ has Ksp = 3.3 × 10⁻⁹ (slightly more soluble but still low). Molar solubility (s) is the number of moles of the salt that dissolve per litre of solution; it is related to Ksp through the stoichiometry of dissolution."},
    {"type": "callout", "style": "info", "title": "Predicting Precipitation: Q vs. Ksp", "content": "To predict whether a precipitate will form when two solutions are mixed, calculate the ion product Q_sp using the initial concentrations after mixing. If Q_sp > Ksp, the solution is supersaturated and a precipitate will form until Q_sp equals Ksp. If Q_sp < Ksp, the solution is unsaturated and no precipitate forms. If Q_sp = Ksp, the system is at equilibrium. This is the same logic as comparing Q to K for any equilibrium system."},
    {"type": "heading", "level": 2, "text": "The Common Ion Effect on Solubility"},
    {"type": "text", "content": "The common ion effect is the decrease in solubility of a sparingly soluble salt caused by the presence of a soluble compound that shares one of its ions. Adding a common ion shifts the dissolution equilibrium toward the solid (Le Chatelier''s principle), reducing the amount that dissolves. For example, the molar solubility of AgCl in pure water is √Ksp = √(1.8 × 10⁻¹⁰) ≈ 1.3 × 10⁻⁵ mol/L, but in 0.10 mol/L NaCl solution, [Cl⁻] is already 0.10 mol/L, so [Ag⁺] = Ksp/[Cl⁻] = 1.8 × 10⁻¹⁰ / 0.10 = 1.8 × 10⁻⁹ mol/L — roughly 7 000 times lower. This principle is applied in uranium processing to selectively precipitate uranyl compounds from complex ore leachate solutions."},
    {"type": "heading", "level": 2, "text": "Selective Precipitation and Water Treatment"},
    {"type": "text", "content": "Selective precipitation exploits differences in Ksp values to separate a mixture of metal ions by adding an appropriate precipitating agent at controlled concentration. As the precipitant is added gradually, the least soluble salt (smallest Ksp) begins to precipitate first. By carefully controlling the concentration of the precipitant, one ion can be substantially removed before the next begins to precipitate. This technique is used in mine water treatment to remove heavy metals (lead, cadmium, arsenic) from drainage before it is released to the environment. Saskatchewan''s uranium mines at Cigar Lake and McArthur River operate sophisticated water treatment circuits that use selective precipitation of hydroxides, sulfides, and carbonates to meet strict environmental discharge standards."},
    {"type": "callout", "style": "example", "title": "Worked Example: Molar Solubility from Ksp", "content": "Question: Calculate the molar solubility of calcium fluoride, CaF₂, in pure water at 25 °C. Ksp(CaF₂) = 3.4 × 10⁻¹¹.\n\nStep 1: Write the dissolution equation and Ksp expression:\nCaF₂(s) ⇌ Ca²⁺(aq) + 2F⁻(aq)\nKsp = [Ca²⁺][F⁻]² = 3.4 × 10⁻¹¹\n\nStep 2: Let s = molar solubility. Then [Ca²⁺] = s and [F⁻] = 2s.\nKsp = (s)(2s)² = 4s³ = 3.4 × 10⁻¹¹\ns³ = 8.5 × 10⁻¹² → s = (8.5 × 10⁻¹²)^(1/3)\ns = 2.04 × 10⁻⁴ mol/L\n\nAnswer: The molar solubility of CaF₂ is approximately 2.0 × 10⁻⁴ mol/L."},
    {"type": "quiz", "question": "Which of the following will decrease the solubility of BaSO₄ (Ksp = 1.1 × 10⁻¹⁰) in water?", "options": ["Adding distilled water", "Adding Na₂SO₄ solution", "Increasing temperature", "Adding HCl solution"], "correctIndex": 1, "explanation": "Adding Na₂SO₄ introduces SO₄²⁻ ions — a common ion with BaSO₄. This shifts the dissolution equilibrium toward the solid (Le Chatelier''s principle), reducing solubility. Distilled water dilutes ions slightly but the system re-dissolves to maintain Ksp; temperature effects depend on the sign of ΔH for dissolution; HCl has no common ion with BaSO₄."},
    {"type": "quiz", "question": "Two solutions are mixed: 50 mL of 0.002 mol/L AgNO₃ and 50 mL of 0.002 mol/L NaCl. Ksp(AgCl) = 1.8 × 10⁻¹⁰. Will a precipitate form?", "options": ["No — Q < Ksp", "Yes — Q > Ksp", "No — the solution is exactly at equilibrium", "Impossible to determine without temperature data"], "correctIndex": 1, "explanation": "After mixing, each concentration is halved: [Ag⁺] = [Cl⁻] = 0.001 mol/L. Q_sp = (0.001)(0.001) = 1.0 × 10⁻⁶. Since Q_sp (1.0 × 10⁻⁶) > Ksp (1.8 × 10⁻¹⁰), the solution is supersaturated and AgCl will precipitate."}
  ]'::jsonb,
  '[
    {"term": "Solubility Product Constant (Ksp)", "definition": "The equilibrium constant for the dissolution of a sparingly soluble ionic compound; equals the product of ion concentrations, each raised to the power of its stoichiometric coefficient."},
    {"term": "Molar Solubility (s)", "definition": "The number of moles of a sparingly soluble salt that dissolve per litre of solution to reach equilibrium."},
    {"term": "Common Ion Effect", "definition": "The decrease in solubility of a sparingly soluble salt caused by the presence of a soluble compound that shares one of the salt''s ions."},
    {"term": "Ion Product (Q_sp)", "definition": "The product of ion concentrations calculated from actual (non-equilibrium) concentrations; compared to Ksp to predict whether precipitation will occur."},
    {"term": "Selective Precipitation", "definition": "The technique of adding a precipitating agent gradually to separate ions with different Ksp values by precipitating the least soluble species first."},
    {"term": "Supersaturated Solution", "definition": "A solution in which the ion product (Q_sp) exceeds Ksp, causing precipitation to occur until equilibrium is restored."},
    {"term": "Complex Ion", "definition": "A metal ion bonded to one or more ligands; complex ion formation can dramatically increase the solubility of an otherwise sparingly soluble salt."}
  ]'::jsonb,
  NULL,
  37, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 9: Organic Chemistry — Structure & Naming
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 9, 'Organic Chemistry: Structure & Naming', 'organic-chemistry-structure-and-naming',
  'Carbon''s bonding versatility, the major classes of hydrocarbons, functional groups, and systematic IUPAC nomenclature — the language of organic chemistry.',
  '[
    {"type": "heading", "level": 1, "text": "Organic Chemistry: Structure & Naming"},
    {"type": "text", "content": "Organic chemistry is the study of compounds based on carbon. The sheer diversity of carbon compounds — more than 10 million known — arises from carbon''s unique ability to form four covalent bonds, bond to itself in chains and rings of almost unlimited length, and bond with a variety of other elements. Organic chemistry underlies the petroleum and natural gas industry that has long contributed to Saskatchewan''s economy, the pharmaceutical industry, food science, polymer manufacturing, and the biochemistry of life itself."},
    {"type": "heading", "level": 2, "text": "Hydrocarbons: Alkanes, Alkenes, and Alkynes"},
    {"type": "text", "content": "Hydrocarbons contain only carbon and hydrogen. Alkanes are saturated hydrocarbons — all carbon-carbon bonds are single bonds (C−C). They follow the general formula CₙH₂ₙ₊₂ and are named with the suffix -ane: methane (CH₄), ethane (C₂H₆), propane (C₃H₈), butane (C₄H₁₀). Alkanes are relatively unreactive (they resist acids, bases, and oxidising agents under normal conditions) and are the primary components of natural gas and petroleum. Alkenes contain at least one carbon-carbon double bond (C=C), follow the formula CₙH₂ₙ for non-cyclic structures, and are named with the suffix -ene: ethene (ethylene), propene (propylene). Alkynes contain at least one carbon-carbon triple bond (C≡C), follow CₙH₂ₙ₋₂, and use the suffix -yne: ethyne (acetylene). Alkenes and alkynes are described as unsaturated and are more reactive than alkanes due to the pi bonds in their multiple bonds."},
    {"type": "callout", "style": "info", "title": "Structural Isomers", "content": "Structural isomers have the same molecular formula but different connectivity of atoms, giving them different physical and chemical properties. For example, both n-butane and isobutane (2-methylpropane) have the formula C₄H₁₀ but different boiling points and reactivities. The number of possible structural isomers grows rapidly with molecular size — C₁₀H₂₂ has 75 structural isomers. Stereoisomers (including geometric cis/trans isomers and enantiomers) share the same connectivity but differ in spatial arrangement — a distinction critical in pharmaceuticals, where mirror-image molecules can have dramatically different biological effects."},
    {"type": "heading", "level": 2, "text": "Aromatic Compounds"},
    {"type": "text", "content": "Aromatic compounds contain a benzene ring — a cyclic, planar structure with delocalized pi electrons described by resonance structures. Benzene (C₆H₆) and its derivatives are stabilised by this electron delocalization and resist addition reactions, instead undergoing electrophilic aromatic substitution. Common aromatic compounds include toluene (used in paint thinners), xylenes (solvents), and naphthalene. Polycyclic aromatic hydrocarbons (PAHs), formed by incomplete combustion of organic matter, are environmental pollutants of concern in Saskatchewan''s industrial areas."},
    {"type": "heading", "level": 2, "text": "Functional Groups"},
    {"type": "text", "content": "A functional group is an atom or group of atoms attached to the carbon skeleton that determines the characteristic reactions of the molecule. Key functional groups include: alcohols (−OH, e.g., ethanol), halides (−X, e.g., chloroform), aldehydes (−CHO), ketones (C=O within the chain), carboxylic acids (−COOH), esters (−COO−), amines (−NH₂), and amides (−CONH₂). Each functional group has predictable reactivity and characteristic spectroscopic signals that allow identification. Canola oil contains esters (triglycerides) of long-chain fatty acids; ethanol produced by fermentation of Saskatchewan wheat and barley contains an alcohol functional group; the herbicide 2,4-D used widely in prairie agriculture contains both a carboxylic acid and a chloride functional group."},
    {"type": "callout", "style": "example", "title": "Worked Example: IUPAC Naming of an Alkane", "content": "Question: Name the following compound using IUPAC nomenclature:\nCH₃−CH(CH₃)−CH₂−CH₂−CH₃\n\nStep 1: Find the longest continuous carbon chain. The main chain has 5 carbons: pentane.\nStep 2: Identify substituents. There is a methyl group (−CH₃) branching from C2 of the main chain.\nStep 3: Number the main chain from the end nearest the substituent: the methyl is on C2 (not C4).\nStep 4: Name the compound: 2-methylpentane.\n\nVerification: If numbered from the other end, the methyl would be on C4 — a higher number, so our direction is correct."},
    {"type": "heading", "level": 2, "text": "IUPAC Nomenclature"},
    {"type": "text", "content": "IUPAC (International Union of Pure and Applied Chemistry) nomenclature provides a systematic, unambiguous name for every organic compound. The steps are: (1) Find the longest continuous carbon chain — this is the parent chain, named using the Greek/Latin prefix for the number of carbons plus the appropriate suffix (−ane, −ene, −yne, −ol, −al, −one, −oic acid, etc.). (2) Number the chain from the end nearest the first branch or functional group to give substituents the lowest possible numbers. (3) Name each substituent with its position number (methyl, ethyl, propyl, etc.). (4) Alphabetise substituents (ignoring multiplying prefixes di-, tri-, etc.). (5) Assemble: positions-substituents-parent chain + functional group suffix."},
    {"type": "quiz", "question": "What is the IUPAC name for CH₃CH₂CH₂OH?", "options": ["Propan-1-ol", "1-propanol", "Propyl alcohol", "Both A and B are acceptable IUPAC names"], "correctIndex": 0, "explanation": "The longest chain has 3 carbons (prop-), the functional group is an alcohol (−ol), and the OH is on carbon 1. The current preferred IUPAC name is propan-1-ol (with the locant immediately before the suffix). The name 1-propanol is commonly used and widely accepted in older literature."},
    {"type": "quiz", "question": "Which of the following pairs are structural isomers?", "options": ["CH₃CH₃ and CH₂=CH₂", "CH₃CH₂CH₃ and CH₃CH(CH₃)CH₃ (wait — these have different formulas)", "C₄H₁₀ as n-butane and C₄H₁₀ as isobutane", "Cis-2-butene and trans-2-butene"], "correctIndex": 2, "explanation": "Structural isomers have the same molecular formula but different connectivity. n-Butane (CH₃CH₂CH₂CH₃) and isobutane (2-methylpropane, (CH₃)₃CH) both have the formula C₄H₁₀ but different carbon skeletons — they are structural isomers. Cis- and trans-2-butene are stereoisomers (same connectivity, different spatial arrangement), not structural isomers."}
  ]'::jsonb,
  '[
    {"term": "Alkane", "definition": "A saturated hydrocarbon in which all carbon-carbon bonds are single bonds; general formula CₙH₂ₙ₊₂; named with the suffix -ane."},
    {"term": "Alkene", "definition": "An unsaturated hydrocarbon containing at least one carbon-carbon double bond; named with the suffix -ene."},
    {"term": "Alkyne", "definition": "An unsaturated hydrocarbon containing at least one carbon-carbon triple bond; named with the suffix -yne."},
    {"term": "Functional Group", "definition": "An atom or group of atoms attached to the carbon skeleton of an organic molecule that determines its characteristic chemical reactions."},
    {"term": "Structural Isomer", "definition": "One of two or more compounds with the same molecular formula but different connectivity of atoms."},
    {"term": "Stereoisomer", "definition": "One of two or more compounds with the same molecular formula and connectivity but different spatial arrangements of atoms."},
    {"term": "IUPAC Nomenclature", "definition": "The systematic naming rules developed by the International Union of Pure and Applied Chemistry that provide an unambiguous name for every organic compound."},
    {"term": "Aromatic Compound", "definition": "An organic compound containing a benzene ring or similar cyclic structure with delocalized pi electrons, characterised by unusual stability."},
    {"term": "Saturated Hydrocarbon", "definition": "A hydrocarbon containing only single carbon-carbon bonds; cannot incorporate additional hydrogen atoms without breaking a bond."}
  ]'::jsonb,
  NULL,
  38, false)
RETURNING id INTO v_ch;

-- ----------------------------------------------------------------------------
-- Chapter 10: Organic Chemistry — Reactions & Applications
-- ----------------------------------------------------------------------------
INSERT INTO textbook_chapters (tenant_id, textbook_id, chapter_number, title, slug, description, content, key_terms, indigenous_connection, estimated_minutes, is_published)
VALUES (v_tenant, v_book, 10, 'Organic Chemistry: Reactions & Applications', 'organic-chemistry-reactions-and-applications',
  'Major organic reaction types — addition, substitution, elimination, and condensation — plus polymers, biodegradable materials, and connections to biochemistry and Saskatchewan industry.',
  '[
    {"type": "heading", "level": 1, "text": "Organic Chemistry: Reactions & Applications"},
    {"type": "text", "content": "The structural diversity of organic compounds explored in Chapter 9 is matched by a rich diversity of chemical reactions. Organic reactions transform one functional group into another, build large molecules from small ones, and break complex structures into simpler fragments. These transformations underpin plastics manufacturing, pharmaceutical synthesis, food processing, and the biochemistry of metabolism. In Saskatchewan, organic chemistry connects directly to the canola and pulse crop industries, natural gas upgrading, and the growing sector of bio-based plastics and fuels."},
    {"type": "heading", "level": 2, "text": "Addition Reactions"},
    {"type": "text", "content": "Addition reactions occur when atoms or groups of atoms are added across a multiple bond, converting a double or triple bond into a single or double bond. The pi bond is broken and two new sigma bonds form. Hydrogenation — addition of H₂ across a double bond, catalysed by Ni, Pt, or Pd — is used industrially to convert unsaturated vegetable oils (like canola oil) into semi-solid fats (margarine). Halogenation — addition of X₂ (Br₂ or Cl₂) across a double bond — is used as a test for unsaturation: an alkene rapidly decolourises bromine water. Hydration — addition of H₂O across a double bond in the presence of an acid catalyst — converts alkenes to alcohols, an important step in producing ethanol from ethylene. Markovnikov''s rule predicts the regiochemistry of these additions: the hydrogen adds to the carbon already bearing more hydrogens (i.e., the H goes where the H''s are)."},
    {"type": "callout", "style": "info", "title": "Substitution Reactions", "content": "In a substitution reaction, one atom or group is replaced by another. Alkanes undergo free-radical halogenation: a halogen atom replaces a hydrogen atom when the reaction is initiated by UV light or heat. The mechanism involves three stages: initiation (homolytic cleavage of X₂ to give halogen radicals), propagation (the radical attacks the alkane, producing a new radical in a chain reaction), and termination (two radicals combine). Aromatic compounds undergo electrophilic aromatic substitution — an electrophile (Br⁺, NO₂⁺, −SO₃H) replaces a ring hydrogen while the aromatic system is preserved."},
    {"type": "heading", "level": 2, "text": "Elimination Reactions and Esterification"},
    {"type": "text", "content": "Elimination reactions remove atoms or groups from adjacent carbons to form a new pi bond, converting an alcohol or alkyl halide to an alkene. For example, when ethanol is heated with concentrated H₂SO₄ above 170 °C, water is eliminated to produce ethylene: CH₃CH₂OH → CH₂=CH₂ + H₂O. Esterification — a condensation reaction between a carboxylic acid and an alcohol — produces an ester and water: RCOOH + HO−R'' → RCOO−R'' + H₂O. Esters are responsible for the characteristic fruity aromas of many foods (ethyl ethanoate in pear flavouring; isoamyl acetate in banana). Biodiesel — increasingly important for sustainable fuel in Saskatchewan''s agricultural sector — is produced by transesterification of canola oil triglycerides with methanol, replacing the glycerol backbone with methyl groups."},
    {"type": "heading", "level": 2, "text": "Polymers"},
    {"type": "text", "content": "A polymer is a large molecule composed of many repeating monomer units linked by covalent bonds. Addition polymers form when monomers with double bonds react by addition without producing any by-product: polyethylene (from ethylene), polypropylene (from propylene), polyvinyl chloride/PVC (from vinyl chloride), and polystyrene (from styrene) are all produced by radical or ionic addition polymerisation. Condensation polymers form when monomers react and release a small molecule (usually water or HCl) at each link: nylon (from a diamine and a dioic acid), polyester (from a diol and a dicarboxylic acid), and polylactic acid (PLA, from lactic acid derived from fermented sugars) are condensation polymers. PLA and other bioplastics derived from Saskatchewan crop biomass are gaining traction as biodegradable alternatives to petroleum-based plastics."},
    {"type": "callout", "style": "example", "title": "Worked Example: Identifying Reaction Type", "content": "Question: Classify each of the following reactions and identify the organic product:\n\n(a) CH₂=CH₂ + HBr → ?\n(b) CH₃CH₂OH + CH₃COOH → ? (acid catalyst)\n(c) CH₃CH₂Br + KOH (ethanol, heat) → ?\n\n(a) Addition of HBr across the double bond (Markovnikov): product is CH₃CH₂Br (bromoethane).\n(b) Esterification (condensation): carboxylic acid + alcohol → ester + water. Product is CH₃COOCH₂CH₃ (ethyl ethanoate) + H₂O.\n(c) Elimination: KOH removes HBr (H from one carbon, Br from the adjacent carbon). Product is CH₂=CH₂ (ethene) + KBr + H₂O."},
    {"type": "heading", "level": 2, "text": "Connections to Biochemistry"},
    {"type": "text", "content": "Organic chemistry and biochemistry share a common molecular language. The proteins studied in Chapter 1 are polypeptides — condensation polymers of amino acids. DNA and RNA are condensation polymers of nucleotides. Fats are esters of glycerol with fatty acids. Carbohydrates are polyhydroxy aldehydes or ketones. The breakdown of glucose during cellular respiration (Chapter 3) involves a sequence of organic reactions — isomerisations, phosphorylations, oxidations, and eliminations — that ultimately release the energy stored in C−H bonds. Understanding organic reaction mechanisms thus provides the molecular foundation for understanding all of metabolism and the action of drugs, hormones, and toxins in living systems."},
    {"type": "quiz", "question": "Canola oil is reacted with hydrogen gas in the presence of a palladium catalyst. This reaction is best classified as:", "options": ["Esterification", "Halogenation", "Hydrogenation (addition)", "Elimination"], "correctIndex": 2, "explanation": "Hydrogenation is an addition reaction in which H₂ is added across carbon-carbon double bonds. In canola oil, the unsaturated fatty acid chains contain C=C double bonds; adding H₂ across these bonds (catalysed by Pd, Ni, or Pt) converts liquid unsaturated oil to a more solid saturated fat — the process used to make margarine."},
    {"type": "quiz", "question": "Polylactic acid (PLA) is formed when lactic acid molecules react with each other, releasing water at each step. PLA is best classified as:", "options": ["An addition polymer", "A condensation polymer", "A copolymer made from two different monomers", "An aromatic polymer"], "correctIndex": 1, "explanation": "Condensation polymers form when monomers link together with the release of a small molecule (here, water) at each bond. Lactic acid has both an −OH and a −COOH group; these react with each other repeatedly to form the polyester PLA, releasing one water molecule per monomer incorporated."}
  ]'::jsonb,
  '[
    {"term": "Addition Reaction", "definition": "A reaction in which atoms or groups of atoms are added across a double or triple bond, reducing the degree of unsaturation."},
    {"term": "Substitution Reaction", "definition": "A reaction in which one atom or group is replaced by another atom or group, leaving the carbon skeleton intact."},
    {"term": "Elimination Reaction", "definition": "A reaction in which atoms are removed from adjacent carbons to form a new pi bond, increasing the degree of unsaturation."},
    {"term": "Esterification", "definition": "A condensation reaction between a carboxylic acid and an alcohol that produces an ester and water, catalysed by a strong acid."},
    {"term": "Addition Polymer", "definition": "A polymer formed by the addition of monomer units containing double bonds without the release of any by-product."},
    {"term": "Condensation Polymer", "definition": "A polymer formed when monomers react and release a small molecule (typically water or HCl) at each linkage."},
    {"term": "Markovnikov''s Rule", "definition": "The rule predicting that in the addition of HX to an alkene, the hydrogen adds to the carbon with more hydrogen substituents and X adds to the carbon with fewer."},
    {"term": "Hydrogenation", "definition": "The addition of H₂ across a carbon-carbon double or triple bond, typically catalysed by a transition metal such as Ni, Pt, or Pd."},
    {"term": "Transesterification", "definition": "A reaction in which the alcohol portion of an ester is exchanged with another alcohol; used to produce biodiesel from vegetable oils."},
    {"term": "Bioplastic", "definition": "A plastic derived from renewable biological feedstocks (such as fermented crop sugars) rather than petroleum, often biodegradable."}
  ]'::jsonb,
  NULL,
  40, false)
RETURNING id INTO v_ch;

END $$;
